const TRACKER_CSS = "@import url('https://fonts.googleapis.com/css2?family=Oswald:wght@500;600;700&family=Inter:wght@400;500;600;700&display=swap');\n\n:root{\n  --bg:#101d16;\n  --bg-alt:#0b1510;\n  --surface:#1b2e22;\n  --surface2:#23392b;\n  --surface3:#2c4534;\n  --line: rgba(238,242,234,0.08);\n  --text:#eef2ea;\n  --muted:#93ab9d;\n  --accent:#d7ff4e;\n  --accent-dim: rgba(215,255,78,0.15);\n  --winner:#6fbf73;\n  --winner-bg: rgba(111,191,115,0.16);\n  --forced:#e08a6b;\n  --forced-bg: rgba(224,138,107,0.16);\n  --unforced:#e3b23c;\n  --unforced-bg: rgba(227,178,60,0.16);\n  --allievo:#59a6ff;\n  --avversario:#ff6f9c;\n  --radius:14px;\n}\n*{box-sizing:border-box;}\nhtml,body{margin:0;padding:0;}\nbody{\n  background:var(--bg);\n  color:var(--text);\n  font-family:'Inter',system-ui,sans-serif;\n  min-height:100vh;\n  -webkit-tap-highlight-color: transparent;\n}\nh1,h2,h3,.num{font-family:'Oswald',system-ui,sans-serif;}\nbutton{font-family:inherit;}\n.app{max-width:900px;margin:0 auto;padding:14px 14px 60px;}\n\n/* ---------- Top nav ---------- */\n.topbar{\n  display:flex;align-items:center;justify-content:space-between;\n  padding:10px 4px 16px;\n}\n.brand{display:flex;align-items:center;gap:10px;}\n.brand-dot{width:10px;height:10px;border-radius:50%;background:var(--accent);box-shadow:0 0 10px var(--accent);}\n.brand-name{font-family:'Oswald';font-weight:600;letter-spacing:1px;text-transform:uppercase;font-size:14px;color:var(--muted);}\n.navlinks{display:flex;gap:6px;}\n.navlinks button{\n  background:none;border:1px solid var(--line);color:var(--muted);\n  padding:7px 12px;border-radius:20px;font-size:12.5px;font-weight:600;cursor:pointer;\n  transition:all .15s;\n}\n.navlinks button.active{background:var(--accent);color:#0c1710;border-color:var(--accent);}\n\n.view{display:none;}\n.view.active{display:block;}\n\n/* ---------- Setup ---------- */\n.setup-card{\n  background:var(--surface);border-radius:var(--radius);padding:28px 22px;\n  border:1px solid var(--line);\n}\n.setup-card h1{font-size:26px;margin:0 0 6px;letter-spacing:.5px;}\n.setup-card p.sub{color:var(--muted);margin:0 0 22px;font-size:14.5px;line-height:1.5;}\n.field{margin-bottom:16px;}\n.field label{display:block;font-size:12.5px;color:var(--muted);margin-bottom:6px;text-transform:uppercase;letter-spacing:.5px;font-weight:600;}\n.field input{\n  width:100%;padding:12px 14px;border-radius:10px;border:1px solid var(--line);\n  background:var(--surface2);color:var(--text);font-size:15px;\n}\n.field input:focus{outline:2px solid var(--accent);outline-offset:1px;}\n.field select{\n  width:100%;padding:12px 14px;border-radius:10px;border:1px solid var(--line);\n  background:var(--surface2);color:var(--text);font-size:14.5px;\n}\n.field select:focus{outline:2px solid var(--accent);outline-offset:1px;}\n.field select option, .field select optgroup{background:#1b2e22;color:#eef2ea;}\n#format-explainer{color:var(--muted);font-size:12.5px;line-height:1.5;margin-top:-6px;min-height:18px;}\n.row2{display:grid;grid-template-columns:1fr 1fr;gap:12px;}\n.btn-primary{\n  width:100%;padding:14px;border:none;border-radius:12px;background:var(--accent);\n  color:#0c1710;font-weight:700;font-size:15.5px;cursor:pointer;margin-top:6px;\n  letter-spacing:.3px;\n}\n.btn-primary:active{transform:scale(.98);}\n.btn-secondary{\n  padding:10px 16px;border-radius:10px;background:var(--surface2);border:1px solid var(--line);\n  color:var(--text);font-weight:600;font-size:13.5px;cursor:pointer;\n}\n.resume-banner{\n  background:var(--accent-dim);border:1px solid var(--accent);border-radius:12px;\n  padding:14px 16px;margin-bottom:18px;display:flex;justify-content:space-between;align-items:center;gap:10px;flex-wrap:wrap;\n}\n.resume-banner span{font-size:13.5px;color:var(--text);}\n\n/* ---------- Scoreboard (signature element) ---------- */\n.scoreboard{\n  background:linear-gradient(180deg,#0c1710,#0a130d);\n  border:1px solid var(--line);\n  border-radius:var(--radius);\n  padding:16px 18px;margin-bottom:14px;\n  position:relative;overflow:hidden;\n}\n.scoreboard::before{\n  content:\"\";position:absolute;inset:0;\n  background:repeating-linear-gradient(180deg, rgba(255,255,255,0.02) 0px, rgba(255,255,255,0.02) 1px, transparent 1px, transparent 3px);\n  pointer-events:none;\n}\n.sb-top{display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;}\n.sb-live{display:flex;align-items:center;gap:6px;color:var(--accent);font-size:11px;font-weight:700;letter-spacing:1.5px;text-transform:uppercase;}\n.sb-live .dot{width:7px;height:7px;border-radius:50%;background:var(--accent);animation:pulse 1.4s infinite;}\n@keyframes pulse{0%,100%{opacity:1;}50%{opacity:.3;}}\n.sb-meta{color:var(--muted);font-size:11.5px;}\n.sb-grid{display:grid;grid-template-columns:1fr auto 1fr;align-items:center;gap:10px;}\n.sb-player{text-align:center;}\n.sb-player .name{font-size:13px;color:var(--muted);text-transform:uppercase;letter-spacing:1px;font-weight:600;margin-bottom:2px;}\n.sb-player.a .name{color:var(--allievo);}\n.sb-player.v .name{color:var(--avversario);}\n.sb-player .score{font-size:44px;line-height:1;font-weight:700;letter-spacing:1px;}\n.sb-mid{color:var(--muted);font-size:20px;font-weight:600;}\n.sb-controls{display:flex;justify-content:center;gap:8px;margin-top:14px;flex-wrap:wrap;}\n.sb-sets-history{display:flex;justify-content:center;gap:6px;margin-bottom:10px;flex-wrap:wrap;}\n.sb-sets-history .setchip{\n  background:var(--surface2);border:1px solid var(--line);border-radius:6px;padding:3px 8px;\n  font-family:'Oswald';font-size:12.5px;color:var(--muted);\n}\n.sb-subrow{display:grid;grid-template-columns:1fr auto 1fr;align-items:center;gap:10px;margin-top:4px;}\n.sb-sub-val{text-align:center;font-family:'Oswald';font-size:22px;font-weight:600;color:var(--text);}\n.sb-sub-val.point{font-size:26px;color:var(--accent);}\n.sb-sub-label{text-align:center;font-size:10.5px;color:var(--muted);text-transform:uppercase;letter-spacing:1px;}\n.sb-format{text-align:center;margin-top:12px;font-size:11.5px;color:var(--muted);}\n.sb-matchover{\n  margin-top:12px;text-align:center;background:var(--accent-dim);border:1px solid var(--accent);\n  border-radius:10px;padding:8px;font-weight:700;color:var(--accent);font-size:13.5px;\n}\n.chip{\n  background:var(--surface2);border:1px solid var(--line);border-radius:20px;\n  padding:6px 12px;font-size:12px;color:var(--muted);display:flex;align-items:center;gap:8px;\n}\n.chip button{background:none;border:none;color:var(--text);font-weight:700;cursor:pointer;font-size:13px;padding:0 4px;}\n.actionbar{display:flex;gap:8px;margin-bottom:16px;flex-wrap:wrap;}\n.actionbar button{flex:1;min-width:120px;}\n.btn-undo{background:var(--surface2);color:var(--forced);border:1px solid var(--line);border-radius:10px;padding:11px;font-weight:700;font-size:13.5px;cursor:pointer;}\n.btn-finish{background:var(--accent);color:#0c1710;border:none;border-radius:10px;padding:11px;font-weight:700;font-size:13.5px;cursor:pointer;}\n\n/* ---------- Legacy result-row/tapbtn (mantenute per compatibilit\u00e0, non pi\u00f9 usate dalla nuova UI) ---------- */\n.result-row{\n  display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:6px;border-radius:10px;overflow:hidden;\n}\n.result-row .rlabel{\n  grid-column:1 / -1;font-size:11px;font-weight:700;padding:5px 10px 0;letter-spacing:.3px;\n}\n.result-row.winner .rlabel{color:var(--winner);}\n.result-row.errori_forzati .rlabel{color:var(--forced);}\n.result-row.errori_non_forzati .rlabel{color:var(--unforced);}\n.tapbtn{\n  border:none;border-radius:10px;padding:12px 8px;cursor:pointer;\n  display:flex;flex-direction:column;align-items:center;gap:2px;\n  font-weight:600;font-size:13px;color:var(--text);\n  transition:transform .08s;\n}\n.tapbtn:active{transform:scale(.95);}\n.tapbtn .pname{font-size:11.5px;text-transform:uppercase;letter-spacing:.5px;opacity:.85;}\n.tapbtn .pcount{font-family:'Oswald';font-size:20px;font-weight:600;}\n.result-row.winner .tapbtn{background:var(--winner-bg);}\n.result-row.errori_forzati .tapbtn{background:var(--forced-bg);}\n.result-row.errori_non_forzati .tapbtn{background:var(--unforced-bg);}\n.tapbtn.a{border-left:3px solid var(--allievo);}\n.tapbtn.v{border-left:3px solid var(--avversario);}\n\n.simple-shot-body{padding:6px 4px 4px;}\n.servizio-row{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:8px;}\n.servizio-row .rlabel{grid-column:1/-1;font-size:11.5px;font-weight:700;color:var(--muted);text-transform:uppercase;letter-spacing:.5px;padding:0 10px 4px;}\n\n/* Selettore zona errore (campo semplificato) \u2014 dove \u00e8 finita la palla */\n.error-zone-overlay{\n  position:fixed;inset:0;background:rgba(6,12,8,0.78);z-index:1000;\n  display:flex;align-items:center;justify-content:center;padding:20px;\n}\n.error-zone-box{background:var(--surface);border:1px solid var(--line);border-radius:var(--radius);padding:18px;max-width:340px;width:100%;}\n.error-zone-box h4{margin:0 0 12px;text-align:center;font-family:'Oswald';font-size:15px;color:var(--text);}\n.court-zone-svg{transition:fill .1s;}\n.court-zone-svg:active{opacity:.7;}\n.court-zone-legend{display:flex;justify-content:space-around;margin:10px 0 14px;font-size:11.5px;color:var(--muted);}\n.btn-skip-zone{width:100%;background:none;border:1px solid var(--line);color:var(--muted);border-radius:9px;padding:9px;font-size:13px;cursor:pointer;}\n\n/* Sezioni legacy: tenute solo per compatibilit\u00e0 stilistica minima */\n.subfase-block{margin:10px 0 4px;}\n.subfase-label{\n  font-size:11.5px;color:var(--muted);text-transform:uppercase;letter-spacing:1px;font-weight:700;\n  margin:10px 4px 6px;\n}\n\n/* ---------- Redesign: griglia categorie 2 colonne ---------- */\n.category-grid{\n  display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:10px;\n}\n.category-tile{\n  display:flex;align-items:center;gap:8px;\n  border:1px solid var(--line);border-radius:10px;padding:12px 10px;\n  background:var(--surface2);color:var(--text);font-weight:600;font-size:13px;\n  cursor:pointer;transition:all .12s;\n}\n.category-tile .tile-dot{width:10px;height:10px;border-radius:50%;flex-shrink:0;}\n.category-tile.active{background:var(--surface3);border-color:var(--accent);box-shadow:0 0 0 1px var(--accent) inset;}\n.category-tile:active{transform:scale(.97);}\n\n.active-category-panel{\n  background:var(--surface);border:1px solid var(--line);border-radius:12px;padding:12px;margin-bottom:14px;min-height:60px;\n}\n\n/* fase (Attacco/Manovra/Difesa) e risposta (1a/2a palla): pillole grandi, ben distinguibili */\n.subfase-pills{display:flex;gap:6px;margin-bottom:10px;}\n.subfase-pill{\n  flex:1;padding:10px 6px;border-radius:9px;border:1.5px solid var(--line);background:var(--surface2);\n  color:var(--muted);font-weight:700;font-size:12.5px;text-transform:uppercase;letter-spacing:.4px;cursor:pointer;\n}\n.subfase-pill.active{background:var(--accent-dim);border-color:var(--accent);color:var(--accent);}\n\n/* direzione: lungolinea / diagonale, facoltativa */\n.direction-toggle{display:flex;gap:6px;margin-bottom:12px;}\n.direction-pill{\n  flex:1;padding:7px 6px;border-radius:8px;border:1px solid var(--line);background:var(--surface2);\n  color:var(--muted);font-size:11.5px;font-weight:600;cursor:pointer;\n}\n.direction-pill.active{background:var(--surface3);border-color:var(--allievo);color:var(--text);}\n\n/* righe risultato compatte: winner/errori ben distinti per colore E per posizione */\n.compact-row{margin-bottom:6px;}\n.compact-rlabel{font-size:10.5px;font-weight:700;text-transform:uppercase;letter-spacing:.4px;margin-bottom:4px;}\n.compact-row.winner .compact-rlabel{color:var(--winner);}\n.compact-row.errori_forzati .compact-rlabel{color:var(--forced);}\n.compact-row.errori_non_forzati .compact-rlabel{color:var(--unforced);}\n.compact-btn-row{display:grid;grid-template-columns:1fr 1fr;gap:6px;}\n.tapbtn-compact{\n  border:none;border-radius:8px;padding:9px 6px;cursor:pointer;\n  display:flex;align-items:center;justify-content:center;gap:6px;\n  font-weight:600;font-size:12px;color:var(--text);transition:transform .08s;\n}\n.tapbtn-compact:active{transform:scale(.94);}\n.tapbtn-compact .pname{font-size:10.5px;text-transform:uppercase;letter-spacing:.3px;opacity:.85;}\n.tapbtn-compact .pcount{font-family:'Oswald';font-size:16px;font-weight:600;}\n.compact-row.winner .tapbtn-compact{background:var(--winner-bg);}\n.compact-row.errori_forzati .tapbtn-compact{background:var(--forced-bg);}\n.compact-row.errori_non_forzati .tapbtn-compact{background:var(--unforced-bg);}\n.tapbtn-compact.a{border-left:3px solid var(--allievo);}\n.tapbtn-compact.v{border-left:3px solid var(--avversario);}\n\n/* battitore: sempre visibile, ben in vista, dentro lo scoreboard persistente */\n.serve-banner{\n  display:flex;align-items:center;justify-content:space-between;gap:10px;\n  background:linear-gradient(90deg, rgba(229,72,77,0.18), rgba(229,72,77,0.05));\n  border:1px solid rgba(229,72,77,0.4);border-radius:10px;padding:9px 12px;margin:10px 0 4px;\n}\n.serve-banner .serve-label{font-size:12.5px;}\n.serve-banner .serve-name{font-family:'Oswald';font-weight:600;color:#ff8a8f;}\n.serve-banner button{padding:6px 11px;font-size:11.5px;border-radius:7px;border:1px solid var(--line);background:var(--surface2);color:var(--text);cursor:pointer;}\n\n/* punteggio comprimibile */\n.sb-collapse-btn{\n  position:absolute;top:10px;right:12px;background:none;border:none;color:var(--muted);\n  font-size:16px;cursor:pointer;padding:4px;\n}\n.scoreboard.collapsed .sb-grid,\n.scoreboard.collapsed .sb-current-set,\n.scoreboard.collapsed .sb-current-game,\n.scoreboard.collapsed .sb-games-row,\n.scoreboard.collapsed .sb-points-row,\n.scoreboard.collapsed .sb-sets-history,\n.scoreboard.collapsed .sb-format{display:none !important;}\n.scoreboard{position:relative;}\n\n/* statistiche live durante la partita */\n.live-stats-toggle{width:100%;margin-bottom:10px;}\n.live-stats-panel{\n  background:var(--surface);border:1px solid var(--line);border-radius:12px;padding:14px;margin-bottom:14px;\n}\n.live-stats-grid{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-top:10px;}\n.live-stat-card{background:var(--surface2);border-radius:9px;padding:10px;text-align:center;}\n.live-stat-card .lv{font-family:'Oswald';font-size:17px;}\n.live-stat-card .ll{font-size:9.5px;color:var(--muted);text-transform:uppercase;letter-spacing:.4px;margin-top:2px;}\n\n/* selettore zona errore: overlay con mini-campo interattivo */\n.court-overlay{\n  position:fixed;inset:0;background:rgba(6,12,8,0.78);z-index:1000;\n  display:flex;align-items:center;justify-content:center;padding:20px;\n}\n.court-picker-box{background:var(--surface);border-radius:14px;padding:20px;max-width:320px;width:100%;text-align:center;}\n.court-picker-box h3{margin:0 0 14px;font-size:15px;}\n.mini-court{width:100%;max-width:220px;margin:0 auto 14px;display:block;}\n.mini-court .zone{cursor:pointer;transition:opacity .15s;}\n.mini-court .zone:active{opacity:.6;}\n.zone-btn-row{display:grid;grid-template-columns:1fr 1fr;gap:8px;}\n.zone-btn-row button{\n  padding:11px 8px;border-radius:9px;border:1px solid var(--line);background:var(--surface2);\n  color:var(--text);font-weight:600;font-size:12.5px;cursor:pointer;\n}\n.zone-btn-row button.skip{grid-column:1/-1;background:none;color:var(--muted);border:none;}\n\n/* ---------- Report ---------- */\n.report-header{\n  background:var(--surface);border-radius:var(--radius);padding:20px;margin-bottom:14px;border:1px solid var(--line);\n}\n.report-header h2{margin:0 0 4px;font-size:22px;}\n.report-header .rmeta{color:var(--muted);font-size:13px;}\n.finalscore{display:flex;align-items:center;justify-content:center;gap:20px;margin:18px 0 6px;}\n.finalscore .fs{text-align:center;}\n.finalscore .fs .n{font-size:52px;font-weight:700;line-height:1;}\n.finalscore .fs.a .n{color:var(--allievo);}\n.finalscore .fs.v .n{color:var(--avversario);}\n.finalscore .fs .l{font-size:12px;color:var(--muted);text-transform:uppercase;letter-spacing:1px;margin-top:4px;}\n.finalscore .sep{font-size:26px;color:var(--muted);}\n\n.stat-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(130px,1fr));gap:10px;margin-top:14px;}\n.stat-card{background:var(--surface2);border-radius:10px;padding:12px;text-align:center;border:1px solid var(--line);}\n.stat-card .v{font-family:'Oswald';font-size:22px;font-weight:600;}\n.stat-card .l{font-size:10.5px;color:var(--muted);text-transform:uppercase;letter-spacing:.5px;margin-top:2px;}\n\n.chart-card{\n  background:var(--surface);border-radius:var(--radius);padding:16px;margin-bottom:14px;border:1px solid var(--line);\n}\n.chart-card h3{margin:0 0 12px;font-size:15px;text-transform:uppercase;letter-spacing:.6px;color:var(--muted);font-weight:700;}\n.chart-wrap{position:relative;height:260px;}\n.chart-fallback{\n  height:100%;display:flex;align-items:center;justify-content:center;text-align:center;\n  color:var(--muted);font-size:13px;padding:16px;line-height:1.5;\n}\n.chart-row{display:grid;grid-template-columns:1fr 1fr;gap:14px;}\n@media(max-width:640px){.chart-row{grid-template-columns:1fr;}}\n\n.insights ul{margin:0;padding-left:18px;}\n.insights li{margin-bottom:9px;font-size:14px;line-height:1.5;color:var(--text);}\n.insights li b{color:var(--accent);}\n\n.export-bar{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:16px;}\n.rating-picker{display:flex;gap:6px;flex-wrap:wrap;}\n.rating-btn{\n  width:36px;height:36px;border-radius:9px;border:1px solid var(--line);background:var(--surface2);\n  color:var(--text);cursor:pointer;font-weight:700;font-family:'Oswald';font-size:14px;\n}\n.rating-btn.selected{background:var(--accent);color:#0c1710;border-color:var(--accent);}\n.textarea{\n  width:100%;padding:12px 14px;border-radius:10px;border:1px solid var(--line);\n  background:var(--surface2);color:var(--text);font-family:'Inter';resize:vertical;box-sizing:border-box;\n}\n.export-bar button{flex:1;min-width:130px;}\n\n/* ---------- History ---------- */\n.history-item{\n  background:var(--surface);border:1px solid var(--line);border-radius:12px;padding:14px 16px;\n  margin-bottom:10px;display:flex;justify-content:space-between;align-items:center;cursor:pointer;gap:10px;\n}\n.history-item:hover{border-color:var(--accent);}\n.history-item .hi-l .hi-title{font-weight:700;font-size:14.5px;}\n.history-item .hi-l .hi-date{font-size:12px;color:var(--muted);margin-top:2px;}\n.history-item .hi-score{font-family:'Oswald';font-size:18px;font-weight:600;color:var(--accent);}\n.empty-state{color:var(--muted);text-align:center;padding:40px 10px;font-size:14px;}\n.empty-state .big{font-size:34px;margin-bottom:8px;}\n\n::-webkit-scrollbar{width:8px;height:8px;}\n::-webkit-scrollbar-thumb{background:var(--surface3);border-radius:4px;}\n@media print{\n  .navlinks,.actionbar,.export-bar,.topbar{display:none !important;}\n  body{background:#fff;color:#000;}\n}";
const TRACKER_BODY_HTML = "\n\n  <div class=\"topbar\">\n    <div class=\"brand\"><div class=\"brand-dot\"></div><div class=\"brand-name\">PointLab \u00b7 Tennis</div></div>\n    <div class=\"navlinks\" id=\"navlinks\" style=\"display:none;\">\n      <button data-view=\"tracker\">Live</button>\n      <button data-view=\"report\">Report</button>\n    </div>\n  </div>\n\n  <!-- SETUP VIEW -->\n  <div class=\"view active\" id=\"view-setup\">\n    <div id=\"resume-banner-slot\"></div>\n    <div class=\"setup-card\">\n      <h1>Nuova partita</h1>\n      <p class=\"sub\">Inserisci i nomi dei due giocatori per iniziare a registrare i colpi in tempo reale, sezione per sezione, esattamente come sulla tua scheda cartacea.</p>\n      <div class=\"row2\">\n        <div class=\"field\"><label>Allievo</label><input id=\"inp-allievo\" placeholder=\"Nome allievo\" value=\"Allievo\"></div>\n        <div class=\"field\"><label>Avversario</label><input id=\"inp-avversario\" placeholder=\"Nome avversario\" value=\"Avversario\"></div>\n      </div>\n      <div class=\"row2\">\n        <div class=\"field\"><label>Torneo / Contesto</label><input id=\"inp-torneo\" placeholder=\"Es. Amichevole, Torneo U16...\"></div>\n        <div class=\"field\"><label>Data</label><input id=\"inp-data\" type=\"date\"></div>\n      </div>\n      <div class=\"field\">\n        <label>Superficie</label>\n        <select id=\"inp-superficie\">\n          <option value=\"\">Non specificata</option>\n          <option value=\"terra\">Terra rossa</option>\n          <option value=\"cemento\">Cemento</option>\n          <option value=\"erba\">Erba</option>\n          <option value=\"indoor\">Indoor / PalaTennis</option>\n          <option value=\"altro\">Altro</option>\n        </select>\n      </div>\n      <div class=\"field\">\n        <label>Formato del match</label>\n        <select id=\"inp-format\"></select>\n      </div>\n      <div class=\"field\" id=\"format-explainer\"></div>\n      <div class=\"field\">\n        <label>Chi serve per primo?</label>\n        <select id=\"inp-first-server\">\n          <option value=\"allievo\">Allievo</option>\n          <option value=\"avversario\">Avversario</option>\n        </select>\n        <div class=\"field-hint\">Serve per calcolare automaticamente le statistiche sul servizio (ace%, prima in campo, break point).</div>\n      </div>\n      <button class=\"btn-primary\" id=\"btn-start\">Inizia registrazione \u2192</button>\n    </div>\n  </div>\n\n  <!-- TRACKER VIEW -->\n  <div class=\"view\" id=\"view-tracker\">\n    <div class=\"scoreboard\" id=\"scoreboard-box\">\n      <button class=\"sb-collapse-btn\" id=\"btn-collapse-score\" title=\"Comprimi/espandi punteggio\">\u25be</button>\n      <div class=\"sb-top\">\n        <div class=\"sb-live\"><span class=\"dot\"></span>Live</div>\n        <div class=\"sb-meta\" id=\"sb-meta\">\u2014</div>\n      </div>\n      <div class=\"sb-sets-history\" id=\"sb-sets-history\"></div>\n      <div class=\"sb-grid\">\n        <div class=\"sb-player a\"><div class=\"name\" id=\"sb-name-a\">Allievo</div><div class=\"score\" id=\"sb-score-a\">0</div></div>\n        <div class=\"sb-mid\" id=\"sb-mid-label\">SET</div>\n        <div class=\"sb-player v\"><div class=\"name\" id=\"sb-name-v\">Avversario</div><div class=\"score\" id=\"sb-score-v\">0</div></div>\n      </div>\n      <div class=\"sb-subrow\" id=\"sb-games-row\">\n        <div class=\"sb-sub-val\" id=\"sb-games-a\">0</div>\n        <div class=\"sb-sub-label\">game</div>\n        <div class=\"sb-sub-val\" id=\"sb-games-v\">0</div>\n      </div>\n      <div class=\"sb-subrow\" id=\"sb-points-row\">\n        <div class=\"sb-sub-val point\" id=\"sb-points-a\">0</div>\n        <div class=\"sb-sub-label\" id=\"sb-points-label\">punto</div>\n        <div class=\"sb-sub-val point\" id=\"sb-points-v\">0</div>\n      </div>\n      <div class=\"sb-format\" id=\"sb-format-label\"></div>\n      <div class=\"sb-matchover\" id=\"sb-matchover\" style=\"display:none;\"></div>\n      <div class=\"serve-banner\">\n        <span class=\"serve-label\">\ud83c\udfbe Al servizio: <span class=\"serve-name\" id=\"servizio-current-name\">\u2014</span></span>\n        <button id=\"btn-first-serve-fault\" type=\"button\">1\u00aa fallo</button>\n      </div>\n    </div>\n\n    <div class=\"actionbar\">\n      <button class=\"btn-undo\" id=\"btn-undo\">\u21ba Annulla ultimo</button>\n      <button class=\"btn-finish\" id=\"btn-finish\">Termina partita \u2192 Report</button>\n    </div>\n\n    <button class=\"btn-secondary live-stats-toggle\" id=\"btn-toggle-livestats\">\ud83d\udcca Statistiche live</button>\n    <div class=\"live-stats-panel\" id=\"live-stats-panel\" style=\"display:none;\"></div>\n\n    <div id=\"sections-container\"></div>\n  </div>\n\n  <!-- REPORT VIEW -->\n  <div class=\"view\" id=\"view-report\">\n    <div id=\"report-container\"></div>\n  </div>\n\n";
const TRACKER_SCRIPT = "(function(){\n\nwindow.addEventListener('error', function(e){\n  console.warn('caught global error (app keeps running):', e && e.message);\n});\nwindow.addEventListener('unhandledrejection', function(e){\n  console.warn('caught unhandled rejection (app keeps running):', e && e.reason);\n  e.preventDefault();\n});\n\n/* ============================================================\n   DATA MODEL\n============================================================ */\nconst RESULT_TYPES = [\n  {key:'winner', label:'Winner'},\n  {key:'errori_forzati', label:'Errori Forzati'},\n  {key:'errori_non_forzati', label:'Errori Non Forzati'}\n];\nconst SUBFASI = [\n  {key:'attacco', label:'Attacco'},\n  {key:'manovra', label:'Manovra'},\n  {key:'difesa', label:'Difesa'}\n];\nconst GROUPED_SHOTS = [\n  {key:'diritto', label:'Diritto', color:'#59a6ff'},\n  {key:'rovescio', label:'Rovescio', color:'#d16fe0'}\n];\nconst SIMPLE_SHOTS = [\n  {key:'volee', label:'Vol\u00e9e', color:'#f0932b'},\n  {key:'smash', label:'Smash', color:'#f1d430'},\n  {key:'dropshot', label:'Drop Shot', color:'#3ecf6e'},\n  {key:'back', label:'Back', color:'#5c7cfa'}\n];\nconst RISPOSTA_FASI = [\n  {key:'prima', label:'1\u00aa Palla'},\n  {key:'seconda', label:'2\u00aa Palla'}\n];\n\nfunction emptyLeaf(){ return {allievo:0, avversario:0}; }\nfunction emptyResultSet(){\n  const o = {};\n  RESULT_TYPES.forEach(r => o[r.key] = emptyLeaf());\n  return o;\n}\nfunction initStats(){\n  const s = {};\n  GROUPED_SHOTS.forEach(g=>{\n    s[g.key] = {};\n    SUBFASI.forEach(f => s[g.key][f.key] = emptyResultSet());\n  });\n  SIMPLE_SHOTS.forEach(sh=>{ s[sh.key] = emptyResultSet(); });\n  s.servizio = { ace: emptyLeaf(), doppio_fallo: emptyLeaf() };\n  s.risposta = {};\n  RISPOSTA_FASI.forEach(f => s.risposta[f.key] = emptyResultSet());\n  return s;\n}\n\n/* ============================================================\n   STATE + LOCAL AUTOSAVE\n   Il salvataggio permanente avviene su Supabase solo a fine partita\n   (vedi FINISH MATCH pi\u00f9 sotto). Qui teniamo solo un autosalvataggio\n   locale per non perdere il lavoro in corso in caso di refresh\n   accidentale della pagina, usando localStorage vero del browser\n   (questa non \u00e8 pi\u00f9 una sandbox: \u00e8 un sito vero, localStorage funziona).\n============================================================ */\nlet state = null; // {meta, stats, log}\nlet currentView = 'setup';\nconst LOCAL_KEY = 'mt_current_match';\n\nfunction saveLocal(){\n  try{ localStorage.setItem(LOCAL_KEY, JSON.stringify(state)); }catch(e){}\n}\nfunction loadLocal(){\n  try{ const raw = localStorage.getItem(LOCAL_KEY); return raw ? JSON.parse(raw) : null; }\n  catch(e){ return null; }\n}\nfunction clearLocal(){\n  try{ localStorage.removeItem(LOCAL_KEY); }catch(e){}\n}\n\n/* Debounced autosave: coalesces bursts of taps into one write. */\nlet saveTimer = null;\nfunction scheduleSave(){\n  if(saveTimer) clearTimeout(saveTimer);\n  saveTimer = setTimeout(saveLocal, 400);\n}\n\n/* ============================================================\n   SCORING FORMAT ENGINE\n   format = {\n     matchType: 'sets' | 'tiebreakOnly',\n     setsToWin: 1|2|3,           // best-of-1 / best-of-3 / best-of-5\n     gamesPerSet: 6|4,\n     deuce: 'ad' | 'noad',\n     regularTB: 7|10|5|null,     // tiebreak points for a normal (non-deciding) set; null = advantage set, no tiebreak\n     finalSetRule: 'normal7'|'normal10'|'advantage'|'mtb10'|'mtb7'|null, // only used when setsToWin>1\n     tbPoints: 5|7|10            // only used when matchType==='tiebreakOnly'\n   }\n============================================================ */\nfunction otherPlayer(p){ return p === 'allievo' ? 'avversario' : 'allievo'; }\n\nfunction createMatchState(format){\n  const ms = {\n    format,\n    matchOver:false, winner:null,\n    setsWon:{allievo:0, avversario:0},\n    completedSets:[],\n    currentSetGames:{allievo:0, avversario:0},\n    currentGamePoints:{allievo:0, avversario:0},\n    inTiebreak:false,\n    tiebreakPoints:{allievo:0, avversario:0},\n    tiebreakTarget:null,\n    _setConfig:null\n  };\n  if(format.matchType === 'tiebreakOnly'){\n    ms.inTiebreak = true;\n    ms.tiebreakTarget = format.tbPoints;\n  } else {\n    configureSet(ms);\n  }\n  return ms;\n}\n\nfunction currentSetIndex(ms){ return ms.setsWon.allievo + ms.setsWon.avversario + 1; }\nfunction totalSetsInMatch(ms){ return ms.format.setsToWin * 2 - 1; }\nfunction isDecidingSetSlot(ms){\n  if(ms.format.setsToWin === 1) return false;\n  return currentSetIndex(ms) === totalSetsInMatch(ms);\n}\n\nfunction configureSet(ms){\n  const singleSetMatch = ms.format.setsToWin === 1;\n  let tbEnabled, tbPoints, tiebreakDecidesMatch = false;\n  if(!singleSetMatch && isDecidingSetSlot(ms) && (ms.format.finalSetRule === 'mtb10' || ms.format.finalSetRule === 'mtb7')){\n    tiebreakDecidesMatch = true;\n    tbEnabled = true;\n    tbPoints = ms.format.finalSetRule === 'mtb10' ? 10 : 7;\n  } else if(!singleSetMatch && isDecidingSetSlot(ms) && ms.format.finalSetRule === 'advantage'){\n    tbEnabled = false; tbPoints = null;\n  } else if(!singleSetMatch && isDecidingSetSlot(ms) && ms.format.finalSetRule === 'normal10'){\n    tbEnabled = true; tbPoints = 10;\n  } else {\n    tbEnabled = ms.format.regularTB !== null && ms.format.regularTB !== undefined;\n    tbPoints = ms.format.regularTB;\n  }\n  ms._setConfig = { tbEnabled, tbPoints, gamesTarget: ms.format.gamesPerSet, tiebreakDecidesMatch };\n  if(tiebreakDecidesMatch){\n    ms.inTiebreak = true;\n    ms.tiebreakTarget = tbPoints;\n    ms.tiebreakPoints = {allievo:0, avversario:0};\n  }\n}\n\nfunction scorePoint(ms, winner){\n  if(!ms || ms.matchOver) return;\n  if(ms.format.matchType === 'tiebreakOnly'){ scoreTiebreakOnly(ms, winner); return; }\n  if(ms.inTiebreak){ scoreTiebreakPoint(ms, winner); }\n  else { scoreGamePoint(ms, winner); }\n}\n\nfunction scoreGamePoint(ms, winner){\n  const pts = ms.currentGamePoints;\n  pts[winner]++;\n  const p = pts[winner], o = pts[otherPlayer(winner)];\n  let gameWon = false;\n  if(ms.format.deuce === 'noad'){ if(p >= 4 && p > o) gameWon = true; }\n  else { if(p >= 4 && (p - o) >= 2) gameWon = true; }\n  if(gameWon) winGame(ms, winner);\n}\n\nfunction winGame(ms, winner){\n  ms.currentGamePoints = {allievo:0, avversario:0};\n  ms.currentSetGames[winner]++;\n  const a = ms.currentSetGames.allievo, v = ms.currentSetGames.avversario;\n  const target = ms._setConfig.gamesTarget;\n  const lead = Math.abs(a - v);\n  const leader = a > v ? 'allievo' : 'avversario';\n  if(Math.max(a,v) >= target && lead >= 2){\n    winSet(ms, leader, {allievo:a, avversario:v, tiebreak:null});\n  } else if(ms._setConfig.tbEnabled && a === target && v === target){\n    ms.inTiebreak = true;\n    ms.tiebreakTarget = ms._setConfig.tbPoints;\n    ms.tiebreakPoints = {allievo:0, avversario:0};\n  }\n}\n\nfunction scoreTiebreakPoint(ms, winner){\n  const pts = ms.tiebreakPoints;\n  pts[winner]++;\n  const p = pts[winner], o = pts[otherPlayer(winner)];\n  if(p >= ms.tiebreakTarget && (p - o) >= 2){\n    let setScore;\n    if(ms._setConfig.tiebreakDecidesMatch){\n      setScore = {allievo:pts.allievo, avversario:pts.avversario, tiebreak:null, isMatchTiebreak:true};\n    } else {\n      ms.currentSetGames[winner] += 1;\n      setScore = {allievo:ms.currentSetGames.allievo, avversario:ms.currentSetGames.avversario, tiebreak:{allievo:pts.allievo, avversario:pts.avversario}};\n    }\n    winSet(ms, winner, setScore);\n  }\n}\n\nfunction scoreTiebreakOnly(ms, winner){\n  const pts = ms.tiebreakPoints;\n  pts[winner]++;\n  const p = pts[winner], o = pts[otherPlayer(winner)];\n  if(p >= ms.format.tbPoints && (p - o) >= 2){\n    ms.completedSets.push({allievo:pts.allievo, avversario:pts.avversario, isMatchTiebreak:true});\n    endMatch(ms, winner);\n  }\n}\n\nfunction winSet(ms, winner, setScoreSnapshot){\n  ms.completedSets.push(setScoreSnapshot);\n  ms.setsWon[winner]++;\n  ms.currentSetGames = {allievo:0, avversario:0};\n  ms.currentGamePoints = {allievo:0, avversario:0};\n  ms.inTiebreak = false;\n  ms.tiebreakPoints = {allievo:0, avversario:0};\n  if(ms.setsWon[winner] >= ms.format.setsToWin){\n    endMatch(ms, winner);\n  } else {\n    configureSet(ms);\n  }\n}\n\nfunction endMatch(ms, winner){\n  ms.matchOver = true;\n  ms.winner = winner;\n}\n\nfunction gamePointLabel(a, b){\n  const L = ['0','15','30','40'];\n  if(a < 3 || b < 3) return [L[Math.min(a,3)], L[Math.min(b,3)]];\n  if(a === b) return ['40','40'];\n  if(a - b === 1) return ['Ad','40'];\n  if(b - a === 1) return ['40','Ad'];\n  return [String(a), String(b)];\n}\n\nfunction escapeHtml(str){\n  const div = { '&':'&amp;', '<':'&lt;', '>':'&gt;', '\"':'&quot;', \"'\":'&#39;' };\n  return String(str).replace(/[&<>\"']/g, c => div[c]);\n}\n\nfunction formatSetScore(s){\n  if(s.isMatchTiebreak) return `${s.allievo}-${s.avversario} (match TB)`;\n  if(s.tiebreak) return `${s.allievo}-${s.avversario}(${Math.min(s.tiebreak.allievo,s.tiebreak.avversario)})`;\n  return `${s.allievo}-${s.avversario}`;\n}\n\n/* ============================================================\n   PRESET MATCH FORMATS\n============================================================ */\nconst PRESETS = [\n  // 2 set su 3 - set normali\n  {id:'p01', group:'2 set su 3 (set normali)', label:'2 set su 3 con vantaggi', format:{matchType:'sets',setsToWin:2,gamesPerSet:6,deuce:'ad',regularTB:7,finalSetRule:'normal7'}, note:'Set normali a 6 game, tie-break a 7 sul 6-6, vantaggi nei game.'},\n  {id:'p02', group:'2 set su 3 (set normali)', label:'2 set su 3 no-ad', format:{matchType:'sets',setsToWin:2,gamesPerSet:6,deuce:'noad',regularTB:7,finalSetRule:'normal7'}, note:'Come sopra, ma punto secco sul 40-40.'},\n  {id:'p03', group:'2 set su 3 (set normali)', label:'2 su 3 con vantaggi, 3\u00b0 set advantage', format:{matchType:'sets',setsToWin:2,gamesPerSet:6,deuce:'ad',regularTB:7,finalSetRule:'advantage'}, note:'Il 3\u00b0 set non ha tie-break: si vince con 2 game di vantaggio.'},\n  {id:'p04', group:'2 set su 3 (set normali)', label:'2 su 3 no-ad, 3\u00b0 set advantage', format:{matchType:'sets',setsToWin:2,gamesPerSet:6,deuce:'noad',regularTB:7,finalSetRule:'advantage'}, note:'3\u00b0 set senza tie-break, punto secco nei game.'},\n  {id:'p05', group:'2 set su 3 (set normali)', label:'2 su 3 con vantaggi, tie-break a 10 sul 6-6 del 3\u00b0 set', format:{matchType:'sets',setsToWin:2,gamesPerSet:6,deuce:'ad',regularTB:7,finalSetRule:'normal10'}, note:'3\u00b0 set normale, ma se arriva 6-6 si gioca un tie-break a 10.'},\n  {id:'p06', group:'2 set su 3 (set normali)', label:'2 su 3 no-ad, tie-break a 10 sul 6-6 del 3\u00b0 set', format:{matchType:'sets',setsToWin:2,gamesPerSet:6,deuce:'noad',regularTB:7,finalSetRule:'normal10'}, note:'Come sopra, punto secco sul 40-40.'},\n\n  // match tie-break al posto del 3\u00b0 set\n  {id:'p07', group:'2 set su 3 \u2014 match tie-break al posto del 3\u00b0 set', label:'Match tie-break a 10 al posto del 3\u00b0 set, con vantaggi', format:{matchType:'sets',setsToWin:2,gamesPerSet:6,deuce:'ad',regularTB:7,finalSetRule:'mtb10'}, note:'Sull\\'1 set pari, invece del 3\u00b0 set si gioca subito un tie-break a 10.'},\n  {id:'p08', group:'2 set su 3 \u2014 match tie-break al posto del 3\u00b0 set', label:'Match tie-break a 10 al posto del 3\u00b0 set, no-ad', format:{matchType:'sets',setsToWin:2,gamesPerSet:6,deuce:'noad',regularTB:7,finalSetRule:'mtb10'}, note:'Come sopra, con punto secco nei primi due set.'},\n  {id:'p09', group:'2 set su 3 \u2014 match tie-break al posto del 3\u00b0 set', label:'Match tie-break a 7 al posto del 3\u00b0 set, con vantaggi', format:{matchType:'sets',setsToWin:2,gamesPerSet:6,deuce:'ad',regularTB:7,finalSetRule:'mtb7'}, note:'Sull\\'1 set pari si gioca un tie-break a 7 al posto del 3\u00b0 set.'},\n  {id:'p10', group:'2 set su 3 \u2014 match tie-break al posto del 3\u00b0 set', label:'Match tie-break a 7 al posto del 3\u00b0 set, no-ad', format:{matchType:'sets',setsToWin:2,gamesPerSet:6,deuce:'noad',regularTB:7,finalSetRule:'mtb7'}, note:'Come sopra, punto secco nei primi due set.'},\n\n  // 3 set su 5\n  {id:'p11', group:'3 set su 5', label:'3 set su 5 con vantaggi', format:{matchType:'sets',setsToWin:3,gamesPerSet:6,deuce:'ad',regularTB:7,finalSetRule:'normal7'}, note:'Vince chi arriva a 3 set; tie-break a 7 sul 6-6 in ogni set.'},\n  {id:'p12', group:'3 set su 5', label:'3 set su 5 no-ad', format:{matchType:'sets',setsToWin:3,gamesPerSet:6,deuce:'noad',regularTB:7,finalSetRule:'normal7'}, note:'Come sopra, punto secco sul 40-40.'},\n  {id:'p13', group:'3 set su 5', label:'3 su 5 con vantaggi, 5\u00b0 set advantage', format:{matchType:'sets',setsToWin:3,gamesPerSet:6,deuce:'ad',regularTB:7,finalSetRule:'advantage'}, note:'Il 5\u00b0 set non ha tie-break: si continua a oltranza con 2 game di vantaggio.'},\n  {id:'p14', group:'3 set su 5', label:'3 su 5 no-ad, 5\u00b0 set advantage', format:{matchType:'sets',setsToWin:3,gamesPerSet:6,deuce:'noad',regularTB:7,finalSetRule:'advantage'}, note:'5\u00b0 set senza tie-break, punto secco negli altri set.'},\n  {id:'p15', group:'3 set su 5', label:'3 su 5 con vantaggi, tie-break a 10 sul 6-6 del 5\u00b0 set', format:{matchType:'sets',setsToWin:3,gamesPerSet:6,deuce:'ad',regularTB:7,finalSetRule:'normal10'}, note:'5\u00b0 set normale, ma sul 6-6 si gioca un tie-break a 10.'},\n  {id:'p16', group:'3 set su 5', label:'3 su 5 no-ad, tie-break a 10 sul 6-6 del 5\u00b0 set', format:{matchType:'sets',setsToWin:3,gamesPerSet:6,deuce:'noad',regularTB:7,finalSetRule:'normal10'}, note:'Come sopra, punto secco sul 40-40.'},\n\n  // match tie-break al posto del 5\u00b0 set\n  {id:'p17', group:'3 set su 5 \u2014 match tie-break al posto del 5\u00b0 set', label:'Match tie-break a 10 al posto del 5\u00b0 set, con vantaggi', format:{matchType:'sets',setsToWin:3,gamesPerSet:6,deuce:'ad',regularTB:7,finalSetRule:'mtb10'}, note:'Sul 2 set pari, invece del 5\u00b0 set si gioca un tie-break a 10.'},\n  {id:'p18', group:'3 set su 5 \u2014 match tie-break al posto del 5\u00b0 set', label:'Match tie-break a 10 al posto del 5\u00b0 set, no-ad', format:{matchType:'sets',setsToWin:3,gamesPerSet:6,deuce:'noad',regularTB:7,finalSetRule:'mtb10'}, note:'Come sopra, punto secco negli altri set.'},\n  {id:'p19', group:'3 set su 5 \u2014 match tie-break al posto del 5\u00b0 set', label:'Match tie-break a 7 al posto del 5\u00b0 set, con vantaggi', format:{matchType:'sets',setsToWin:3,gamesPerSet:6,deuce:'ad',regularTB:7,finalSetRule:'mtb7'}, note:'Sul 2 set pari si gioca un tie-break a 7 al posto del 5\u00b0 set.'},\n  {id:'p20', group:'3 set su 5 \u2014 match tie-break al posto del 5\u00b0 set', label:'Match tie-break a 7 al posto del 5\u00b0 set, no-ad', format:{matchType:'sets',setsToWin:3,gamesPerSet:6,deuce:'noad',regularTB:7,finalSetRule:'mtb7'}, note:'Come sopra, punto secco negli altri set.'},\n\n  // short set\n  {id:'p21', group:'Short set', label:'2 su 3 short set con vantaggi', format:{matchType:'sets',setsToWin:2,gamesPerSet:4,deuce:'ad',regularTB:7,finalSetRule:'normal7'}, note:'Set corti a 4 game, tie-break a 7 sul 4-4, vantaggi nei game.'},\n  {id:'p22', group:'Short set', label:'2 su 3 short set no-ad', format:{matchType:'sets',setsToWin:2,gamesPerSet:4,deuce:'noad',regularTB:7,finalSetRule:'normal7'}, note:'Set corti a 4 game, punto secco sul 40-40.'},\n  {id:'p23', group:'Short set', label:'2 su 3 short set + match tie-break a 10 al 3\u00b0 set, con vantaggi', format:{matchType:'sets',setsToWin:2,gamesPerSet:4,deuce:'ad',regularTB:7,finalSetRule:'mtb10'}, note:'Primi due set corti; sull\\'1 pari, tie-break a 10 al posto del 3\u00b0.'},\n  {id:'p24', group:'Short set', label:'2 su 3 short set + match tie-break a 10 al 3\u00b0 set, no-ad', format:{matchType:'sets',setsToWin:2,gamesPerSet:4,deuce:'noad',regularTB:7,finalSetRule:'mtb10'}, note:'Come sopra, punto secco nei set corti.'},\n  {id:'p25', group:'Short set', label:'2 su 3 short set + match tie-break a 7 al 3\u00b0 set, con vantaggi', format:{matchType:'sets',setsToWin:2,gamesPerSet:4,deuce:'ad',regularTB:7,finalSetRule:'mtb7'}, note:'Primi due set corti; sull\\'1 pari, tie-break a 7 al posto del 3\u00b0.'},\n  {id:'p26', group:'Short set', label:'2 su 3 short set + match tie-break a 7 al 3\u00b0 set, no-ad', format:{matchType:'sets',setsToWin:2,gamesPerSet:4,deuce:'noad',regularTB:7,finalSetRule:'mtb7'}, note:'Come sopra, punto secco nei set corti.'},\n  {id:'p27', group:'Short set', label:'Short set con tie-break a 5 punti, con vantaggi', format:{matchType:'sets',setsToWin:1,gamesPerSet:4,deuce:'ad',regularTB:5,finalSetRule:null}, note:'Un solo set corto a 4 game; sul 4-4 tie-break ridotto a 5 punti.'},\n  {id:'p28', group:'Short set', label:'Short set con tie-break a 5 punti, no-ad', format:{matchType:'sets',setsToWin:1,gamesPerSet:4,deuce:'noad',regularTB:5,finalSetRule:null}, note:'Come sopra, con punto secco sul 40-40: il formato pi\u00f9 rapido.'},\n\n  // set unico\n  {id:'p29', group:'Set unico', label:'Set unico a 6 game con vantaggi', format:{matchType:'sets',setsToWin:1,gamesPerSet:6,deuce:'ad',regularTB:null,finalSetRule:null}, note:'Un solo set normale, senza tie-break: si vince con 2 game di vantaggio.'},\n  {id:'p30', group:'Set unico', label:'Set unico a 6 game no-ad', format:{matchType:'sets',setsToWin:1,gamesPerSet:6,deuce:'noad',regularTB:null,finalSetRule:null}, note:'Un solo set, senza tie-break, punto secco sul 40-40.'},\n  {id:'p31', group:'Set unico', label:'Set unico con tie-break a 7 sul 6-6, con vantaggi', format:{matchType:'sets',setsToWin:1,gamesPerSet:6,deuce:'ad',regularTB:7,finalSetRule:null}, note:'Set singolo classico con tie-break a 7 sul 6-6.'},\n  {id:'p32', group:'Set unico', label:'Set unico con tie-break a 7 sul 6-6, no-ad', format:{matchType:'sets',setsToWin:1,gamesPerSet:6,deuce:'noad',regularTB:7,finalSetRule:null}, note:'Come sopra, punto secco sul 40-40.'},\n  {id:'p33', group:'Set unico', label:'Set unico con tie-break a 10 sul 6-6, con vantaggi', format:{matchType:'sets',setsToWin:1,gamesPerSet:6,deuce:'ad',regularTB:10,finalSetRule:null}, note:'Set singolo con tie-break lungo a 10 sul 6-6.'},\n  {id:'p34', group:'Set unico', label:'Set unico con tie-break a 10 sul 6-6, no-ad', format:{matchType:'sets',setsToWin:1,gamesPerSet:6,deuce:'noad',regularTB:10,finalSetRule:null}, note:'Come sopra, punto secco sul 40-40.'},\n  {id:'p35', group:'Set unico', label:'Short set unico con vantaggi', format:{matchType:'sets',setsToWin:1,gamesPerSet:4,deuce:'ad',regularTB:7,finalSetRule:null}, note:'Un solo set corto a 4 game, tie-break a 7 sul 4-4.'},\n  {id:'p36', group:'Set unico', label:'Short set unico no-ad', format:{matchType:'sets',setsToWin:1,gamesPerSet:4,deuce:'noad',regularTB:7,finalSetRule:null}, note:'Un solo set corto, punto secco sul 40-40.'},\n\n  // solo tie-break\n  {id:'p37', group:'Solo tie-break', label:'Tie-break secco a 7', format:{matchType:'tiebreakOnly',tbPoints:7}, note:'Si gioca solo un tie-break: vince chi arriva a 7 con 2 punti di vantaggio.'},\n  {id:'p38', group:'Solo tie-break', label:'Tie-break secco a 10', format:{matchType:'tiebreakOnly',tbPoints:10}, note:'Si gioca solo un match tie-break a 10 punti, vantaggio di 2.'},\n  {id:'p39', group:'Solo tie-break', label:'Tie-break secco a 5', format:{matchType:'tiebreakOnly',tbPoints:5}, note:'Versione lampo: vince chi arriva a 5 punti con 2 di vantaggio.'},\n];\n\nconst POPULAR_IDS = ['p01','p02','p07','p08','p24','p30','p38'];\n\nfunction buildFormatSelect(){\n  const sel = document.getElementById('inp-format');\n  sel.innerHTML = '';\n  const popGroup = document.createElement('optgroup');\n  popGroup.label = '\u2b50 Pi\u00f9 usati nei circoli';\n  POPULAR_IDS.forEach(id=>{\n    const p = PRESETS.find(x=>x.id===id);\n    const opt = document.createElement('option');\n    opt.value = p.id; opt.textContent = p.label;\n    popGroup.appendChild(opt);\n  });\n  sel.appendChild(popGroup);\n\n  const groups = [];\n  PRESETS.forEach(p=>{ if(!groups.includes(p.group)) groups.push(p.group); });\n  groups.forEach(g=>{\n    const og = document.createElement('optgroup');\n    og.label = g;\n    PRESETS.filter(p=>p.group===g).forEach(p=>{\n      const opt = document.createElement('option');\n      opt.value = p.id; opt.textContent = p.label;\n      og.appendChild(opt);\n    });\n    sel.appendChild(og);\n  });\n  updateFormatExplainer();\n  sel.addEventListener('change', updateFormatExplainer);\n}\nfunction updateFormatExplainer(){\n  const sel = document.getElementById('inp-format');\n  const p = PRESETS.find(x=>x.id===sel.value) || PRESETS[0];\n  document.getElementById('format-explainer').textContent = p.note;\n}\n\nfunction newMatchState(allievo, avversario, torneo, data, formatId, firstServer, superficie){\n  const preset = PRESETS.find(p=>p.id===formatId) || PRESETS[0];\n  return {\n    meta:{ allievo: allievo||'Allievo', avversario: avversario||'Avversario', torneo: torneo||'', data: data|| new Date().toISOString().slice(0,10), superficie: superficie||'', startedAt: Date.now(), formatId: preset.id, formatLabel: preset.label, athleteId: window.__MT_ATHLETE__ ? window.__MT_ATHLETE__.id : null, firstServer: firstServer || 'allievo' },\n    stats: initStats(),\n    log: [],\n    match: createMatchState(JSON.parse(JSON.stringify(preset.format))),\n    serveNumberFlag: 1 // 1=stiamo giocando la prima di servizio, 2=stiamo giocando la seconda (dopo un fallo)\n  };\n}\n\nfunction getPath(obj, path){\n  let cur = obj;\n  for(const p of path){ cur = cur[p]; }\n  return cur;\n}\n\nfunction inc(path, player, extra){\n  extra = extra || {};\n  const leaf = getPath(state.stats, path);\n  leaf[player] += 1;\n  const resultKey = path[path.length-1];\n  const pointWinner = (resultKey === 'winner' || resultKey === 'ace') ? player : otherPlayer(player);\n  const msBefore = state.match ? JSON.parse(JSON.stringify(state.match)) : null;\n  const setNumber = state.match ? currentSetIndex(state.match) : null;\n  const gameNumber = state.match ? (state.match.currentSetGames.allievo + state.match.currentSetGames.avversario + 1) : null;\n\n  // Servizio: chi sta servendo, che numero di servizio, eventuale palla break \u2014\n  // calcolato con le funzioni condivise esposte dal componente React (lib/matchEngine.js).\n  let server = null, serveNumber = null, wasBreakPoint = false, breakPointResult = null;\n  if(state.match && window.__MT_GET_SERVER__){\n    server = window.__MT_GET_SERVER__(state.match, state.meta.firstServer);\n    serveNumber = state.serveNumberFlag || 1;\n    if(!state.match.inTiebreak){\n      const returner = otherPlayer(server);\n      const cgp = state.match.currentGamePoints;\n      wasBreakPoint = window.__MT_WOULD_WIN_GAME__(cgp[returner], cgp[server], state.match.format.deuce);\n    }\n  }\n\n  if(state.match) scorePoint(state.match, pointWinner);\n  if(wasBreakPoint) breakPointResult = (pointWinner === server) ? 'saved' : 'converted';\n\n  state.log.push({\n    path: path.slice(), player, ts: Date.now(), pointWinner, set: setNumber, game: gameNumber, msBefore,\n    server, serveNumber, wasBreakPoint, breakPointResult,\n    direction: extra.direction || null,\n    errorZone: extra.errorZone || null,\n  });\n  state.serveNumberFlag = 1; // il prossimo punto riparte sempre dalla prima di servizio\n  scheduleSave();\n  renderAllCounts();\n  renderScoreboard();\n  refreshLiveStatsIfOpen();\n}\n\nfunction toggleFirstServeFault(){\n  state.serveNumberFlag = (state.serveNumberFlag === 2) ? 1 : 2;\n  renderScoreboard();\n}\n\nfunction undo(){\n  const entry = state.log.pop();\n  if(!entry) return;\n  const leaf = getPath(state.stats, entry.path);\n  leaf[entry.player] = Math.max(0, leaf[entry.player]-1);\n  if(entry.msBefore) state.match = entry.msBefore;\n  if(entry.serveNumber) state.serveNumberFlag = entry.serveNumber;\n  scheduleSave();\n  renderAllCounts();\n  renderScoreboard();\n}\n\n/* point-scoring convention:\n   winner -> point to that player\n   errori_forzati / errori_non_forzati -> point to the OTHER player\n   ace -> point to that player\n   doppio_fallo -> point to the OTHER player\n*/\nfunction addToScore(score, resultKey, leaf){\n  if(resultKey === 'winner' || resultKey === 'ace'){\n    score.allievo += leaf.allievo;\n    score.avversario += leaf.avversario;\n  } else {\n    score.allievo += leaf.avversario;\n    score.avversario += leaf.allievo;\n  }\n}\n\nfunction computeScore(stats){\n  const score = {allievo:0, avversario:0};\n  GROUPED_SHOTS.forEach(g=>{\n    SUBFASI.forEach(f=>{\n      RESULT_TYPES.forEach(r=> addToScore(score, r.key, stats[g.key][f.key][r.key]));\n    });\n  });\n  SIMPLE_SHOTS.forEach(sh=>{\n    RESULT_TYPES.forEach(r=> addToScore(score, r.key, stats[sh.key][r.key]));\n  });\n  addToScore(score, 'ace', stats.servizio.ace);\n  addToScore(score, 'doppio_fallo', stats.servizio.doppio_fallo);\n  RISPOSTA_FASI.forEach(f=>{\n    RESULT_TYPES.forEach(r=> addToScore(score, r.key, stats.risposta[f.key][r.key]));\n  });\n  return score;\n}\n\nfunction totalPointsLogged(stats){\n  let t = 0;\n  function sumLeaf(l){ t += l.allievo + l.avversario; }\n  GROUPED_SHOTS.forEach(g=> SUBFASI.forEach(f=> RESULT_TYPES.forEach(r=> sumLeaf(stats[g.key][f.key][r.key]))));\n  SIMPLE_SHOTS.forEach(sh=> RESULT_TYPES.forEach(r=> sumLeaf(stats[sh.key][r.key])));\n  sumLeaf(stats.servizio.ace); sumLeaf(stats.servizio.doppio_fallo);\n  RISPOSTA_FASI.forEach(f=> RESULT_TYPES.forEach(r=> sumLeaf(stats.risposta[f.key][r.key])));\n  return t;\n}\n\n/* ============================================================\n   VIEW SWITCHING\n============================================================ */\nfunction showView(name){\n  currentView = name;\n  document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));\n  document.getElementById('view-'+name).classList.add('active');\n  document.querySelectorAll('#navlinks button').forEach(b=>{\n    b.classList.toggle('active', b.dataset.view === name);\n  });\n  // (history view removed \u2014 history now lives in the coach dashboard)\n}\n\n/* ============================================================\n   BUILD TRACKER UI\n============================================================ */\nconst counterRegistry = []; // {el, path, player} \u2014 tenuto per compatibilit\u00e0, non pi\u00f9 centrale\n\nconst CATEGORY_LIST = [\n  {key:'diritto', label:'Diritto', color:'#59a6ff', type:'grouped'},\n  {key:'rovescio', label:'Rovescio', color:'#d16fe0', type:'grouped'},\n  {key:'servizio', label:'Servizio', color:'#e5484d', type:'servizio'},\n  {key:'volee', label:'Vol\u00e9e', color:'#f0932b', type:'simple'},\n  {key:'smash', label:'Smash', color:'#f1d430', type:'simple'},\n  {key:'dropshot', label:'Drop Shot', color:'#3ecf6e', type:'simple'},\n  {key:'back', label:'Back', color:'#5c7cfa', type:'simple'},\n  {key:'risposta', label:'Risposta', color:'#2dd4c8', type:'risposta'},\n];\n\nfunction makeCompactTapBtn(path, player, playerLabel, isErrorType){\n  const btn = document.createElement('button');\n  btn.className = 'tapbtn-compact ' + (player==='allievo' ? 'a' : 'v');\n  const leaf = getPath(state.stats, path);\n  btn.innerHTML = `<span class=\"pname\">${playerLabel}</span><span class=\"pcount\">${leaf[player]}</span>`;\n  btn.addEventListener('click', ()=>{\n    if(isErrorType){\n      showErrorZonePicker(path, player);\n    } else {\n      inc(path, player, { direction: state.currentDirection || null });\n    }\n  });\n  counterRegistry.push({el: btn.querySelector('.pcount'), path, player});\n  return btn;\n}\n\nfunction buildCompactResultRows(container, basePath){\n  RESULT_TYPES.forEach(rt=>{\n    const row = document.createElement('div');\n    row.className = 'compact-row ' + rt.key;\n    const label = document.createElement('div');\n    label.className = 'compact-rlabel';\n    label.textContent = (rt.key==='winner' ? '\u2713 ' : rt.key==='errori_forzati' ? '\u26a0 ' : '\u2717 ') + rt.label;\n    row.appendChild(label);\n    const btnRow = document.createElement('div');\n    btnRow.className = 'compact-btn-row';\n    const isError = rt.key !== 'winner';\n    btnRow.appendChild(makeCompactTapBtn(basePath.concat(rt.key), 'allievo', state.meta.allievo, isError));\n    btnRow.appendChild(makeCompactTapBtn(basePath.concat(rt.key), 'avversario', state.meta.avversario, isError));\n    row.appendChild(btnRow);\n    container.appendChild(row);\n  });\n}\n\nfunction buildDirectionToggle(container){\n  const wrap = document.createElement('div');\n  wrap.className = 'direction-toggle';\n  const options = [\n    {key:null, label:'\u2014'},\n    {key:'lungolinea', label:'\u2191 Lungolinea'},\n    {key:'diagonale', label:'\u2197 Diagonale'},\n  ];\n  options.forEach(opt=>{\n    const b = document.createElement('button');\n    b.type = 'button';\n    b.className = 'direction-pill' + (state.currentDirection === opt.key ? ' active' : '');\n    b.textContent = opt.label;\n    b.onclick = ()=>{\n      state.currentDirection = opt.key;\n      wrap.querySelectorAll('.direction-pill').forEach(p=>p.classList.remove('active'));\n      b.classList.add('active');\n    };\n    wrap.appendChild(b);\n  });\n  container.appendChild(wrap);\n}\n\nfunction renderActivePanel(){\n  const panel = document.getElementById('active-category-panel');\n  if(!panel) return;\n  panel.innerHTML = '';\n  counterRegistry.length = 0; // evita l'accumulo di riferimenti a bottoni rimossi ad ogni cambio categoria\n  const cat = CATEGORY_LIST.find(c=>c.key===state.activeCategory) || CATEGORY_LIST[0];\n\n  if(cat.type === 'grouped'){\n    const pills = document.createElement('div');\n    pills.className = 'subfase-pills';\n    SUBFASI.forEach(f=>{\n      const b = document.createElement('button');\n      b.type = 'button';\n      b.className = 'subfase-pill' + (state.activeSubfase===f.key ? ' active' : '');\n      b.textContent = f.label;\n      b.onclick = ()=>{ state.activeSubfase = f.key; renderActivePanel(); };\n      pills.appendChild(b);\n    });\n    panel.appendChild(pills);\n    buildDirectionToggle(panel);\n    buildCompactResultRows(panel, [cat.key, state.activeSubfase || 'attacco']);\n  } else if(cat.type === 'simple'){\n    buildDirectionToggle(panel);\n    buildCompactResultRows(panel, [cat.key]);\n  } else if(cat.type === 'servizio'){\n    const row1 = document.createElement('div');\n    row1.className = 'compact-row winner';\n    row1.innerHTML = '<div class=\"compact-rlabel\">\u2713 Ace</div>';\n    const btnRow1 = document.createElement('div'); btnRow1.className = 'compact-btn-row';\n    btnRow1.appendChild(makeCompactTapBtn(['servizio','ace'], 'allievo', state.meta.allievo, false));\n    btnRow1.appendChild(makeCompactTapBtn(['servizio','ace'], 'avversario', state.meta.avversario, false));\n    row1.appendChild(btnRow1);\n    panel.appendChild(row1);\n\n    const row2 = document.createElement('div');\n    row2.className = 'compact-row errori_non_forzati';\n    row2.innerHTML = '<div class=\"compact-rlabel\">\u2717 Doppio Fallo</div>';\n    const btnRow2 = document.createElement('div'); btnRow2.className = 'compact-btn-row';\n    btnRow2.appendChild(makeCompactTapBtn(['servizio','doppio_fallo'], 'allievo', state.meta.allievo, false));\n    btnRow2.appendChild(makeCompactTapBtn(['servizio','doppio_fallo'], 'avversario', state.meta.avversario, false));\n    row2.appendChild(btnRow2);\n    panel.appendChild(row2);\n  } else if(cat.type === 'risposta'){\n    const pills = document.createElement('div');\n    pills.className = 'subfase-pills';\n    RISPOSTA_FASI.forEach(f=>{\n      const b = document.createElement('button');\n      b.type = 'button';\n      b.className = 'subfase-pill' + (state.activeRispostaFase===f.key ? ' active' : '');\n      b.textContent = f.label;\n      b.onclick = ()=>{ state.activeRispostaFase = f.key; renderActivePanel(); };\n      pills.appendChild(b);\n    });\n    panel.appendChild(pills);\n    buildCompactResultRows(panel, ['risposta', state.activeRispostaFase || 'prima']);\n  }\n}\n\nfunction selectCategory(key){\n  state.activeCategory = key;\n  document.querySelectorAll('.category-tile').forEach(t=> t.classList.toggle('active', t.dataset.key===key));\n  renderActivePanel();\n}\n\nfunction buildTrackerSections(){\n  counterRegistry.length = 0;\n  if(!state.activeCategory) state.activeCategory = 'diritto';\n  if(!state.activeSubfase) state.activeSubfase = 'attacco';\n  if(!state.activeRispostaFase) state.activeRispostaFase = 'prima';\n\n  const container = document.getElementById('sections-container');\n  container.innerHTML = '';\n\n  const grid = document.createElement('div');\n  grid.className = 'category-grid';\n  CATEGORY_LIST.forEach(cat=>{\n    const tile = document.createElement('button');\n    tile.type = 'button';\n    tile.className = 'category-tile' + (state.activeCategory===cat.key ? ' active' : '');\n    tile.dataset.key = cat.key;\n    tile.innerHTML = `<span class=\"tile-dot\" style=\"background:${cat.color}\"></span>${cat.label}`;\n    tile.onclick = ()=> selectCategory(cat.key);\n    grid.appendChild(tile);\n  });\n  container.appendChild(grid);\n\n  const panel = document.createElement('div');\n  panel.className = 'active-category-panel';\n  panel.id = 'active-category-panel';\n  container.appendChild(panel);\n\n  renderActivePanel();\n}\n\n/* ---------- Disegno campo da tennis (SVG condiviso: selettore live + report) ---------- */\nfunction courtSVGLines(){\n  // Campo (doppio) x=20..220 y=20..300, singolare inset di 20px per lato,\n  // rete a y=300, linea di servizio a ~171, linea centrale di servizio a x=120.\n  return `\n    <rect x=\"20\" y=\"20\" width=\"200\" height=\"280\" fill=\"none\" stroke=\"rgba(238,242,234,0.55)\" stroke-width=\"2\"/>\n    <line x1=\"40\" y1=\"20\" x2=\"40\" y2=\"300\" stroke=\"rgba(238,242,234,0.35)\" stroke-width=\"1.5\"/>\n    <line x1=\"200\" y1=\"20\" x2=\"200\" y2=\"300\" stroke=\"rgba(238,242,234,0.35)\" stroke-width=\"1.5\"/>\n    <line x1=\"40\" y1=\"171\" x2=\"200\" y2=\"171\" stroke=\"rgba(238,242,234,0.35)\" stroke-width=\"1.5\"/>\n    <line x1=\"120\" y1=\"171\" x2=\"120\" y2=\"300\" stroke=\"rgba(238,242,234,0.35)\" stroke-width=\"1.5\"/>\n    <line x1=\"20\" y1=\"300\" x2=\"220\" y2=\"300\" stroke=\"var(--text)\" stroke-width=\"3\"/>\n  `;\n}\n\n/**\n * Ritorna l'SVG completo del campo. In modalit\u00e0 \"picker\" le 4 zone sono\n * rettangoli cliccabili (data-zone) da collegare via JS. In modalit\u00e0\n * \"heatmap\" accetta {zoneCounts, zoneTotal} e colora/etichetta le zone\n * in base a quanti errori ci sono finiti \u2014 usata nel report finale.\n */\nfunction buildCourtSVG(mode, zoneStats){\n  const zones = [\n    { key:'lungo',    x:20,  y:0,   w:200, h:20,  label:'Lunga' },\n    { key:'rete',     x:20,  y:300, w:200, h:25,  label:'In rete' },\n    { key:'largo_sx', x:0,   y:20,  w:20,  h:280, label:'Larga sx' },\n    { key:'largo_dx', x:220, y:20,  w:20,  h:280, label:'Larga dx' },\n  ];\n  const zoneRects = zones.map(z=>{\n    let fill = 'rgba(215,255,78,0.12)';\n    let extra = '';\n    if(mode === 'heatmap' && zoneStats && zoneStats.zoneTotal > 0){\n      const count = zoneStats.zoneCounts[z.key] || 0;\n      const pct = count / zoneStats.zoneTotal;\n      fill = `rgba(224,138,107,${0.12 + pct*0.75})`;\n      extra = count > 0 ? `<text x=\"${z.x + z.w/2}\" y=\"${z.y + z.h/2}\" text-anchor=\"middle\" dominant-baseline=\"middle\" font-size=\"13\" font-weight=\"700\" fill=\"#fff\">${count}</text>` : '';\n    }\n    const cls = mode === 'picker' ? 'court-zone-svg' : '';\n    const cursor = mode === 'picker' ? 'cursor:pointer;' : '';\n    return `<rect class=\"${cls}\" data-zone=\"${z.key}\" x=\"${z.x}\" y=\"${z.y}\" width=\"${z.w}\" height=\"${z.h}\" fill=\"${fill}\" stroke=\"rgba(238,242,234,0.15)\" style=\"${cursor}\"/>${extra}`;\n  }).join('');\n\n  return `\n  <svg viewBox=\"0 0 240 325\" style=\"width:100%;max-width:280px;display:block;margin:0 auto;\">\n    ${zoneRects}\n    ${courtSVGLines()}\n  </svg>`;\n}\n\n/* ---------- Selettore zona errore (dove \u00e8 finita la palla) ---------- */\nfunction showErrorZonePicker(path, player){\n  const overlay = document.createElement('div');\n  overlay.className = 'error-zone-overlay';\n  overlay.innerHTML = `\n    <div class=\"error-zone-box\">\n      <h4>Dove \u00e8 finita la palla?</h4>\n      ${buildCourtSVG('picker')}\n      <div class=\"court-zone-legend\">\n        <span>\u2b06\ufe0f Lunga</span><span>\ud83e\udd45 Rete</span><span>\u2b05\ufe0f\u27a1\ufe0f Larga</span>\n      </div>\n      <button class=\"btn-skip-zone\" type=\"button\">Salta (non specificare)</button>\n    </div>\n  `;\n  document.body.appendChild(overlay);\n\n  function finish(zone){\n    overlay.remove();\n    inc(path, player, { direction: state.currentDirection || null, errorZone: zone || null });\n  }\n  overlay.querySelectorAll('.court-zone-svg').forEach(z=>{\n    z.addEventListener('click', ()=> finish(z.dataset.zone));\n  });\n  overlay.querySelector('.btn-skip-zone').onclick = ()=> finish(null);\n  overlay.addEventListener('click', (e)=>{ if(e.target === overlay) finish(null); });\n}\n\n/* ---------- Statistiche live durante la partita ---------- */\nfunction computeLiveTotals(){\n  const totals = { winner:{allievo:0,avversario:0}, errori_forzati:{allievo:0,avversario:0}, errori_non_forzati:{allievo:0,avversario:0} };\n  function addSet(rs){\n    RESULT_TYPES.forEach(rt=>{\n      totals[rt.key].allievo += rs[rt.key].allievo;\n      totals[rt.key].avversario += rs[rt.key].avversario;\n    });\n  }\n  GROUPED_SHOTS.forEach(g=> SUBFASI.forEach(f=> addSet(state.stats[g.key][f.key])));\n  SIMPLE_SHOTS.forEach(sh=> addSet(state.stats[sh.key]));\n  RISPOSTA_FASI.forEach(f=> addSet(state.stats.risposta[f.key]));\n  return totals;\n}\n\nfunction computeLiveShotBreakdown(){\n  // net (winner - errori) per l'allievo, per ciascun tipo di colpo \u2014 cos\u00ec\n  // vede in tempo reale quale colpo sta rendendo di pi\u00f9 durante la partita.\n  function netOfSet(rs){\n    return rs.winner.allievo - (rs.errori_forzati.allievo + rs.errori_non_forzati.allievo);\n  }\n  const rows = [];\n  GROUPED_SHOTS.forEach(g=>{\n    let net = 0;\n    SUBFASI.forEach(f=> net += netOfSet(state.stats[g.key][f.key]));\n    rows.push({ label:g.label, net });\n  });\n  SIMPLE_SHOTS.forEach(sh=>{\n    rows.push({ label:sh.label, net: netOfSet(state.stats[sh.key]) });\n  });\n  return rows;\n}\n\nfunction renderLiveStats(){\n  const panel = document.getElementById('live-stats-panel');\n  if(!panel) return;\n  const t = computeLiveTotals();\n  const ace = state.stats.servizio.ace, df = state.stats.servizio.doppio_fallo;\n  const efA = t.errori_forzati.allievo, enfA = t.errori_non_forzati.allievo;\n  const efV = t.errori_forzati.avversario, enfV = t.errori_non_forzati.avversario;\n  const shotRows = computeLiveShotBreakdown();\n\n  const serveStats = window.__MT_COMPUTE_SERVE_STATS__ ? window.__MT_COMPUTE_SERVE_STATS__(state.log) : null;\n  const a = serveStats ? serveStats.allievo : null;\n\n  const zoneCounts = {}; let zoneTotal = 0;\n  state.log.forEach(e=>{ if(e.player==='allievo' && e.errorZone){ zoneCounts[e.errorZone]=(zoneCounts[e.errorZone]||0)+1; zoneTotal++; } });\n  const ZONE_LABELS_SHORT = { lungo:'Lunga', largo_sx:'Larga sx', largo_dx:'Larga dx', rete:'In rete' };\n  const topZoneEntry = zoneTotal>0 ? Object.entries(zoneCounts).sort((x,y)=>y[1]-x[1])[0] : null;\n\n  const shotRowsHtml = shotRows.map(r=>`\n    <div class=\"row\" style=\"padding:5px 0;font-size:12.5px;border-bottom:1px solid var(--line);\">\n      <span class=\"muted\">${r.label}</span>\n      <span style=\"font-family:'Oswald';font-weight:700;color:${r.net>0?'var(--winner)':r.net<0?'var(--unforced)':'var(--muted)'}\">${r.net>0?'+':''}${r.net}</span>\n    </div>`).join('');\n\n  panel.innerHTML = `\n    <div class=\"live-stats-grid\">\n      <div class=\"live-stat-card\"><div class=\"lv\" style=\"color:var(--winner)\">${t.winner.allievo}</div><div class=\"ll\">Winner ${state.meta.allievo}</div></div>\n      <div class=\"live-stat-card\"><div class=\"lv\" style=\"color:var(--winner)\">${t.winner.avversario}</div><div class=\"ll\">Winner ${state.meta.avversario}</div></div>\n      <div class=\"live-stat-card\"><div class=\"lv\" style=\"color:var(--forced)\">${efA}</div><div class=\"ll\">Err. forzati ${state.meta.allievo}</div></div>\n      <div class=\"live-stat-card\"><div class=\"lv\" style=\"color:var(--unforced)\">${enfA}</div><div class=\"ll\">Err. non forz. ${state.meta.allievo}</div></div>\n      <div class=\"live-stat-card\"><div class=\"lv\" style=\"color:var(--forced)\">${efV}</div><div class=\"ll\">Err. forzati ${state.meta.avversario}</div></div>\n      <div class=\"live-stat-card\"><div class=\"lv\" style=\"color:var(--unforced)\">${enfV}</div><div class=\"ll\">Err. non forz. ${state.meta.avversario}</div></div>\n      <div class=\"live-stat-card\"><div class=\"lv\">${ace.allievo}</div><div class=\"ll\">Ace ${state.meta.allievo}</div></div>\n      <div class=\"live-stat-card\"><div class=\"lv\">${df.allievo}</div><div class=\"ll\">Doppi falli ${state.meta.allievo}</div></div>\n      ${a ? `<div class=\"live-stat-card\"><div class=\"lv\">${a.firstInPct!=null?a.firstInPct+'%':'\u2014'}</div><div class=\"ll\">Prima in campo</div></div>` : ''}\n      ${a ? `<div class=\"live-stat-card\"><div class=\"lv\">${a.bpFaced? a.bpSaved+'/'+a.bpFaced : '\u2014'}</div><div class=\"ll\">Palle break salvate</div></div>` : ''}\n    </div>\n\n    <div style=\"margin-top:14px;\">\n      <div class=\"muted\" style=\"font-size:11px;text-transform:uppercase;letter-spacing:.5px;margin-bottom:4px;\">Rendimento per colpo (${state.meta.allievo})</div>\n      ${shotRowsHtml}\n    </div>\n\n    ${topZoneEntry ? `\n    <div class=\"row\" style=\"margin-top:10px;padding-top:10px;border-top:1px solid var(--line);font-size:12.5px;\">\n      <span class=\"muted\">Zona errori pi\u00f9 frequente</span>\n      <span style=\"font-family:'Oswald';\">${ZONE_LABELS_SHORT[topZoneEntry[0]]||topZoneEntry[0]} (${topZoneEntry[1]}/${zoneTotal})</span>\n    </div>` : ''}\n  `;\n}\n\nfunction refreshLiveStatsIfOpen(){\n  const panel = document.getElementById('live-stats-panel');\n  if(panel && panel.style.display !== 'none') renderLiveStats();\n}\n\nfunction renderAllCounts(){\n  counterRegistry.forEach(c=>{\n    const leaf = getPath(state.stats, c.path);\n    if(c.el) c.el.textContent = leaf[c.player];\n  });\n}\n\nfunction renderScoreboard(){\n  const ms = state.match;\n  document.getElementById('sb-name-a').textContent = state.meta.allievo;\n  document.getElementById('sb-name-v').textContent = state.meta.avversario;\n  document.getElementById('sb-meta').textContent = (state.meta.torneo ? state.meta.torneo+' \u00b7 ' : '') + state.meta.data;\n  document.getElementById('sb-format-label').textContent = state.meta.formatLabel || '';\n\n  const servizioNameEl = document.getElementById('servizio-current-name');\n  if(servizioNameEl && ms && window.__MT_GET_SERVER__){\n    const server = window.__MT_GET_SERVER__(ms, state.meta.firstServer);\n    servizioNameEl.textContent = state.meta[server];\n    const faultBtn = document.getElementById('btn-first-serve-fault');\n    if(faultBtn){\n      const isSecond = state.serveNumberFlag === 2;\n      faultBtn.textContent = isSecond ? '2\u00aa in corso \u2713' : '1\u00aa fallo';\n      faultBtn.style.background = isSecond ? 'var(--unforced-bg)' : '';\n      faultBtn.style.color = isSecond ? 'var(--text)' : '';\n    }\n  }\n\n  // completed sets history chips\n  const hist = document.getElementById('sb-sets-history');\n  hist.innerHTML = ms.completedSets.map(s=>`<span class=\"setchip\">${formatSetScore(s)}</span>`).join('');\n\n  const overBanner = document.getElementById('sb-matchover');\n  if(ms.matchOver){\n    overBanner.style.display = 'block';\n    const winnerName = ms.winner === 'allievo' ? state.meta.allievo : state.meta.avversario;\n    overBanner.textContent = `\ud83c\udfc6 Partita conclusa \u2014 vince ${winnerName}`;\n  } else {\n    overBanner.style.display = 'none';\n  }\n\n  if(ms.format.matchType === 'tiebreakOnly'){\n    // whole match is a single tiebreak: show just the tiebreak points big, hide sets/games rows\n    document.getElementById('sb-mid-label').textContent = 'TB';\n    document.getElementById('sb-score-a').textContent = ms.tiebreakPoints.allievo;\n    document.getElementById('sb-score-v').textContent = ms.tiebreakPoints.avversario;\n    document.getElementById('sb-games-row').style.display = 'none';\n    document.getElementById('sb-points-row').style.display = 'none';\n    return;\n  }\n\n  document.getElementById('sb-mid-label').textContent = 'SET';\n  document.getElementById('sb-score-a').textContent = ms.setsWon.allievo;\n  document.getElementById('sb-score-v').textContent = ms.setsWon.avversario;\n\n  document.getElementById('sb-games-row').style.display = 'grid';\n  document.getElementById('sb-games-a').textContent = ms.currentSetGames.allievo;\n  document.getElementById('sb-games-v').textContent = ms.currentSetGames.avversario;\n\n  document.getElementById('sb-points-row').style.display = 'grid';\n  if(ms.inTiebreak){\n    document.getElementById('sb-points-label').textContent = `tie-break a ${ms.tiebreakTarget}`;\n    document.getElementById('sb-points-a').textContent = ms.tiebreakPoints.allievo;\n    document.getElementById('sb-points-v').textContent = ms.tiebreakPoints.avversario;\n  } else {\n    document.getElementById('sb-points-label').textContent = 'punto';\n    const [la, lv] = gamePointLabel(ms.currentGamePoints.allievo, ms.currentGamePoints.avversario);\n    document.getElementById('sb-points-a').textContent = la;\n    document.getElementById('sb-points-v').textContent = lv;\n  }\n}\n\n/* ============================================================\n   SETUP FLOW\n============================================================ */\nfunction checkResume(){\n  const existing = loadLocal();\n  const slot = document.getElementById('resume-banner-slot');\n  const currentAthleteId = window.__MT_ATHLETE__ ? window.__MT_ATHLETE__.id : null;\n  if(existing && existing.meta && existing.meta.athleteId === currentAthleteId){\n    slot.innerHTML = `<div class=\"resume-banner\">\n      <span>Partita in corso: <b>${existing.meta.allievo}</b> vs <b>${existing.meta.avversario}</b> \u2014 riprendi da dove avevi lasciato.</span>\n      <button class=\"btn-secondary\" id=\"btn-resume\">Riprendi \u2192</button>\n    </div>`;\n    document.getElementById('btn-resume').addEventListener('click', ()=>{\n      state = existing;\n      if(!state.match){\n        state.match = createMatchState(JSON.parse(JSON.stringify(PRESETS[0].format)));\n        state.meta.formatId = PRESETS[0].id;\n        state.meta.formatLabel = PRESETS[0].label;\n      }\n      if(!state.meta.firstServer) state.meta.firstServer = 'allievo';\n      if(!state.serveNumberFlag) state.serveNumberFlag = 1;\n      document.getElementById('navlinks').style.display='flex';\n      buildTrackerSections();\n      renderScoreboard();\n      showView('tracker');\n    });\n  } else {\n    slot.innerHTML = '';\n  }\n}\n\ndocument.getElementById('btn-start').addEventListener('click', async ()=>{\n  const allievo = document.getElementById('inp-allievo').value.trim() || 'Allievo';\n  const avversario = document.getElementById('inp-avversario').value.trim() || 'Avversario';\n  const torneo = document.getElementById('inp-torneo').value.trim();\n  const data = document.getElementById('inp-data').value || new Date().toISOString().slice(0,10);\n  const superficie = document.getElementById('inp-superficie').value;\n  const formatId = document.getElementById('inp-format').value;\n  const firstServer = document.getElementById('inp-first-server').value;\n  state = newMatchState(allievo, avversario, torneo, data, formatId, firstServer, superficie);\n  document.getElementById('navlinks').style.display='flex';\n  buildTrackerSections();\n  renderScoreboard();\n  showView('tracker');\n  saveLocal();\n});\n\ndocument.getElementById('btn-undo').addEventListener('click', undo);\n\ndocument.getElementById('btn-first-serve-fault').addEventListener('click', toggleFirstServeFault);\n\ndocument.getElementById('btn-collapse-score').addEventListener('click', ()=>{\n  const box = document.getElementById('scoreboard-box');\n  box.classList.toggle('collapsed');\n  document.getElementById('btn-collapse-score').textContent = box.classList.contains('collapsed') ? '\u25b8' : '\u25be';\n});\n\ndocument.getElementById('btn-toggle-livestats').addEventListener('click', ()=>{\n  const panel = document.getElementById('live-stats-panel');\n  const willShow = panel.style.display === 'none';\n  panel.style.display = willShow ? '' : 'none';\n  if(willShow) renderLiveStats();\n});\n\n/* ============================================================\n   FINISH MATCH -> REPORT\n   Salvataggio VERO e permanente su Supabase, collegato a questo\n   allievo e a questo maestro.\n============================================================ */\ndocument.getElementById('btn-finish').addEventListener('click', async ()=>{\n  state.meta.endedAt = Date.now();\n  const record = { meta: state.meta, stats: state.stats, log: state.log, match: state.match };\n  state = null;\n  clearLocal();\n  // Mostriamo subito il report dai dati in memoria: il salvataggio nel\n  // database non deve mai bloccare o nascondere la partita appena finita.\n  document.getElementById('report-container').innerHTML = '<div class=\"empty-state\">Generazione report\u2026</div>';\n  showView('report');\n  renderReport(record);\n\n  const saveBanner = document.getElementById('save-status');\n  try{\n    const sb = window.__MT_SUPABASE__;\n    const { data: inserted, error } = await sb.from('matches').insert({\n      academy_id: window.__MT_ACADEMY_ID__,\n      athlete_id: window.__MT_ATHLETE__.id,\n      staff_id: window.__MT_STAFF_ID__ || null,\n      recorded_by_name: window.__MT_STAFF_NAME__ || null,\n      meta: record.meta,\n      stats: record.stats,\n      log: record.log,\n      match: record.match,\n    }).select('id').single();\n    if(error) throw error;\n    if(saveBanner){ saveBanner.textContent = '\u2705 Partita salvata nel database.'; saveBanner.style.color = 'var(--accent)'; }\n    showReviewWidget(inserted.id, record);\n  }catch(e){\n    console.warn('salvataggio su Supabase fallito:', e);\n    if(saveBanner){\n      saveBanner.textContent = '\u26a0\ufe0f Non sono riuscito a salvare questa partita nel database. Esporta subito JSON/CSV qui sotto per non perdere i dati, poi contatta il supporto.';\n      saveBanner.style.color = 'var(--forced)';\n    }\n  }\n});\n\n/* Widget mostrato subito dopo il salvataggio: il maestro pu\u00f2 aggiungere\n   una valutazione (1-10) e un commento PRIMA che l'allievo veda la\n   partita \u2014 resta nascosta a lui finch\u00e9 non viene pubblicata. */\nfunction showReviewWidget(matchId, record){\n  const container = document.getElementById('report-container');\n  const widget = document.createElement('div');\n  widget.className = 'chart-card';\n  widget.id = 'coach-review-widget';\n  widget.innerHTML = `\n    <h3>\ud83d\udc68\u200d\ud83c\udfeb Report per l'allievo</h3>\n    <p class=\"muted\" style=\"margin:-4px 0 12px;\">Visibile all'allievo solo dopo che lo pubblichi. Puoi anche saltare questo passaggio e farlo pi\u00f9 tardi dalla scheda dell'allievo.</p>\n    <div class=\"rating-picker\" id=\"rw-rating\" style=\"margin-bottom:14px;\"></div>\n    <div class=\"field\"><label>Sintesi</label><textarea class=\"textarea\" id=\"rw-summary\" rows=\"2\" placeholder=\"Com'\u00e8 andata la partita in generale\"></textarea></div>\n    <div class=\"field\"><label>Cosa ha funzionato</label><textarea class=\"textarea\" id=\"rw-worked\" rows=\"2\"></textarea></div>\n    <div class=\"field\"><label>Cosa migliorare</label><textarea class=\"textarea\" id=\"rw-improve\" rows=\"2\"></textarea></div>\n    <div class=\"field\"><label>Obiettivo per il prossimo allenamento</label><textarea class=\"textarea\" id=\"rw-goal\" rows=\"2\"></textarea></div>\n    <div class=\"row\" style=\"gap:8px; margin-top:12px;\">\n      <button class=\"btn-secondary\" id=\"rw-skip\" style=\"flex:1;\">Salta per ora</button>\n      <button class=\"btn-finish\" id=\"rw-publish\" style=\"flex:1;\">\ud83d\udce4 Pubblica per l'allievo</button>\n    </div>\n  `;\n  container.appendChild(widget);\n\n  let selectedRating = null;\n  const ratingWrap = widget.querySelector('#rw-rating');\n  for(let i=1;i<=10;i++){\n    const b = document.createElement('button');\n    b.type = 'button';\n    b.className = 'rating-btn';\n    b.textContent = i;\n    b.onclick = ()=>{\n      selectedRating = (selectedRating === i) ? null : i;\n      ratingWrap.querySelectorAll('.rating-btn').forEach(btn=> btn.classList.remove('selected'));\n      if(selectedRating) b.classList.add('selected');\n    };\n    ratingWrap.appendChild(b);\n  }\n\n  widget.querySelector('#rw-skip').onclick = ()=> widget.remove();\n\n  widget.querySelector('#rw-publish').onclick = async ()=>{\n    const summary = widget.querySelector('#rw-summary').value.trim();\n    const worked = widget.querySelector('#rw-worked').value.trim();\n    const improve = widget.querySelector('#rw-improve').value.trim();\n    const goal = widget.querySelector('#rw-goal').value.trim();\n    const sb = window.__MT_SUPABASE__;\n    const publishBtn = widget.querySelector('#rw-publish');\n    publishBtn.disabled = true; publishBtn.textContent = 'Pubblicazione\u2026';\n    try{\n      const update = {\n        coach_rating: selectedRating,\n        coach_summary: summary || null,\n        coach_worked_well: worked || null,\n        coach_to_improve: improve || null,\n        coach_next_goal: goal || null,\n        published_to_athlete: true\n      };\n      const { error } = await sb.from('matches').update(update).eq('id', matchId);\n      if(error) throw error;\n      Object.assign(record, update);\n      renderReport(record); // ridisegna il report includendo la valutazione appena pubblicata\n      fetch('/api/notify/match-published', {\n        method: 'POST',\n        headers: { 'Content-Type': 'application/json' },\n        body: JSON.stringify({ matchId })\n      }).catch(()=>{}); // non bloccante: se l'email fallisce, la pubblicazione resta comunque valida\n    }catch(e){\n      alert('Errore nel pubblicare la valutazione: '+e.message);\n      publishBtn.disabled = false; publishBtn.textContent = \"\ud83d\udce4 Pubblica per l'allievo\";\n    }\n  };\n}\n\nfunction goToNewMatch(){\n  document.getElementById('resume-banner-slot').innerHTML = '';\n  showView('setup');\n}\n\n/* ============================================================\n   ANALYSIS HELPERS\n============================================================ */\nfunction netForResultSet(rs){\n  // net \"value\" per player from a {winner, errori_forzati, errori_non_forzati} block\n  let a=0, v=0;\n  a += rs.winner.allievo; v += rs.winner.avversario;\n  a += rs.errori_forzati.avversario + rs.errori_non_forzati.avversario;\n  v += rs.errori_forzati.allievo + rs.errori_non_forzati.allievo;\n  a -= (rs.errori_forzati.allievo + rs.errori_non_forzati.allievo);\n  v -= (rs.errori_forzati.avversario + rs.errori_non_forzati.avversario);\n  return {allievo:a, avversario:v};\n}\nfunction sumResultSets(list){\n  const total = {winner:emptyLeaf(), errori_forzati:emptyLeaf(), errori_non_forzati:emptyLeaf()};\n  list.forEach(rs=>{\n    RESULT_TYPES.forEach(rt=>{\n      total[rt.key].allievo += rs[rt.key].allievo;\n      total[rt.key].avversario += rs[rt.key].avversario;\n    });\n  });\n  return total;\n}\n\nlet charts = [];\nfunction destroyCharts(){ charts.forEach(c=>{ try{ c.destroy(); }catch(e){} }); charts = []; }\n\nfunction mkChart(canvas, config){\n  if(typeof Chart === 'undefined'){\n    if(canvas && canvas.parentElement){\n      canvas.parentElement.innerHTML = '<div class=\"chart-fallback\">\ud83d\udcca Grafico non disponibile in questo momento (la libreria grafica non si \u00e8 caricata). I dati restano comunque nelle statistiche qui sopra e negli export JSON/CSV.</div>';\n    }\n    return null;\n  }\n  try{\n    const c = new Chart(canvas.getContext('2d'), config);\n    charts.push(c);\n    return c;\n  }catch(e){\n    console.warn('chart render failed (non-fatal):', e);\n    if(canvas && canvas.parentElement){\n      canvas.parentElement.innerHTML = '<div class=\"chart-fallback\">\ud83d\udcca Non sono riuscito a disegnare questo grafico. I dati restano comunque disponibili qui sopra e negli export.</div>';\n    }\n    return null;\n  }\n}\n\nfunction loadScriptOnce(src, timeoutMs){\n  return new Promise((resolve, reject)=>{\n    const s = document.createElement('script');\n    s.src = src;\n    let done = false;\n    const timer = setTimeout(()=>{ if(!done){ done = true; reject(new Error('timeout: '+src)); } }, timeoutMs || 8000);\n    s.onload = ()=>{ if(!done){ done = true; clearTimeout(timer); resolve(); } };\n    s.onerror = ()=>{ if(!done){ done = true; clearTimeout(timer); reject(new Error('failed to load: '+src)); } };\n    document.head.appendChild(s);\n  });\n}\n\nlet chartLoadAttempted = false;\nasync function ensureChartLoaded(){\n  if(typeof Chart !== 'undefined') return true;\n  if(chartLoadAttempted) return typeof Chart !== 'undefined';\n  chartLoadAttempted = true;\n  const sources = [\n    'https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.4/chart.umd.min.js',\n    'https://cdn.jsdelivr.net/npm/chart.js@4.4.4/dist/chart.umd.min.js'\n  ];\n  try{\n    await Promise.any(sources.map(src => loadScriptOnce(src, 4000)));\n  }catch(e){\n    console.warn('Chart.js could not be loaded from any source (non-fatal):', e);\n  }\n  return typeof Chart !== 'undefined';\n}\n\nfunction ensureChartDefaults(){\n  if(typeof Chart === 'undefined') return;\n  Chart.defaults.color = '#93ab9d';\n  Chart.defaults.font.family = \"'Inter', sans-serif\";\n  Chart.defaults.borderColor = 'rgba(255,255,255,0.06)';\n}\n\nasync function renderReport(record){\n  await ensureChartLoaded();\n  ensureChartDefaults();\n  destroyCharts();\n  const stats = record.stats;\n  const meta = record.meta;\n  const ms = record.match;\n  const score = computeScore(stats);\n  const totalPts = totalPointsLogged(stats);\n  const durationMin = meta.endedAt ? Math.max(1, Math.round((meta.endedAt - meta.startedAt)/60000)) : null;\n\n  // ---- zona degli errori (dai dati raccolti col selettore campo) \u2014 calcolata\n  // una volta sola qui, riusata sia nella card visiva sia nell'analisi testuale ----\n  const zoneCounts = {};\n  let zoneTotal = 0;\n  (record.log || []).forEach(e=>{\n    if(e.player === 'allievo' && e.errorZone){\n      zoneCounts[e.errorZone] = (zoneCounts[e.errorZone] || 0) + 1;\n      zoneTotal++;\n    }\n  });\n\n  let bigA = score.allievo, bigV = score.avversario, setsLine = '';\n  if(ms){\n    if(ms.format.matchType === 'tiebreakOnly'){\n      const tb = ms.completedSets[0];\n      bigA = tb ? tb.allievo : 0; bigV = tb ? tb.avversario : 0;\n    } else {\n      bigA = ms.setsWon.allievo; bigV = ms.setsWon.avversario;\n    }\n    setsLine = ms.completedSets.map(s=>`<span class=\"setchip\">${formatSetScore(s)}</span>`).join('');\n  }\n\n  const container = document.getElementById('report-container');\n  container.innerHTML = `\n    <div class=\"report-header\">\n      <h2>${meta.allievo} vs ${meta.avversario}</h2>\n      <div class=\"rmeta\">${meta.torneo ? meta.torneo+' \u00b7 ' : ''}${meta.data}${durationMin? ' \u00b7 '+durationMin+' min' : ''}${meta.formatLabel? ' \u00b7 '+meta.formatLabel : ''}${meta.superficie ? ' \u00b7 '+({terra:'Terra rossa',cemento:'Cemento',erba:'Erba',indoor:'Indoor'}[meta.superficie] || meta.superficie) : ''}</div>\n      ${record.recorded_by_name ? `<div class=\"rmeta\" style=\"margin-top:2px;\">Registrata da: <b style=\"color:var(--text);\">${escapeHtml(record.recorded_by_name)}</b></div>` : ''}\n      <div class=\"finalscore\">\n        <div class=\"fs a\"><div class=\"n\">${bigA}</div><div class=\"l\">${meta.allievo}</div></div>\n        <div class=\"sep\">\u2013</div>\n        <div class=\"fs v\"><div class=\"n\">${bigV}</div><div class=\"l\">${meta.avversario}</div></div>\n      </div>\n      ${setsLine ? `<div class=\"sb-sets-history\" style=\"margin-top:6px;\">${setsLine}</div>` : ''}\n      ${ms && ms.matchOver ? `<div style=\"text-align:center;color:var(--muted);font-size:12.5px;margin-top:6px;\">\ud83c\udfc6 Vince ${ms.winner==='allievo'?meta.allievo:meta.avversario}</div>` : ''}\n      <div id=\"save-status\" style=\"text-align:center;font-size:12.5px;margin-top:10px;color:var(--muted);\">Salvataggio in corso\u2026</div>\n      <div class=\"stat-grid\" id=\"stat-grid\"></div>\n    </div>\n\n    <div class=\"export-bar\">\n      <button class=\"btn-secondary\" id=\"btn-export-json\">\u2b07 Esporta JSON</button>\n      <button class=\"btn-secondary\" id=\"btn-export-csv\">\u2b07 Esporta CSV</button>\n      <button class=\"btn-secondary\" id=\"btn-print\">\ud83d\udda8 Stampa report</button>\n      <button class=\"btn-secondary\" id=\"btn-newmatch\">\uff0b Nuova partita</button>\n      <a class=\"btn-secondary\" id=\"btn-back-athlete\" href=\"/dashboard/athlete/${window.__MT_ATHLETE__ ? window.__MT_ATHLETE__.id : ''}\" style=\"text-decoration:none; text-align:center;\">\u2190 Scheda allievo</a>\n    </div>\n\n    ${(record.coach_rating || record.coach_comment || record.coach_summary || record.coach_worked_well || record.coach_to_improve || record.coach_next_goal) ? `\n    <div class=\"chart-card\">\n      <h3>\ud83d\udc68\u200d\ud83c\udfeb Report del maestro</h3>\n      ${record.coach_rating ? `<div style=\"font-family:'Oswald';font-size:30px;color:var(--accent);margin-bottom:10px;\">${record.coach_rating}<span style=\"font-size:15px;color:var(--muted);\">/10</span></div>` : ''}\n      ${record.coach_summary ? `<p style=\"margin:0 0 10px;line-height:1.55;\">${escapeHtml(record.coach_summary)}</p>` : ''}\n      ${record.coach_worked_well ? `<p style=\"margin:0 0 10px;line-height:1.55;\"><b>Cosa ha funzionato:</b> ${escapeHtml(record.coach_worked_well)}</p>` : ''}\n      ${record.coach_to_improve ? `<p style=\"margin:0 0 10px;line-height:1.55;\"><b>Cosa migliorare:</b> ${escapeHtml(record.coach_to_improve)}</p>` : ''}\n      ${record.coach_next_goal ? `<p style=\"margin:0 0 10px;line-height:1.55;\"><b>Obiettivo per il prossimo allenamento:</b> ${escapeHtml(record.coach_next_goal)}</p>` : ''}\n      ${(!record.coach_summary && record.coach_comment) ? `<p style=\"margin:0;line-height:1.55;\">${escapeHtml(record.coach_comment)}</p>` : ''}\n    </div>` : ''}\n\n    ${record.ai_commentary ? `\n    <div class=\"chart-card\">\n      <h3>\ud83d\udcca Analisi tecnica <span style=\"font-size:10.5px;font-weight:500;text-transform:none;letter-spacing:0;color:var(--muted);\">\u2014 AI, supervisionata dal maestro</span></h3>\n      <p style=\"margin:0;line-height:1.65;white-space:pre-line;\">${escapeHtml(record.ai_commentary)}</p>\n    </div>` : ''}\n\n    <div class=\"chart-card\"><h3>Winner vs Errori \u2014 totale partita</h3><div class=\"chart-wrap\"><canvas id=\"c-overview\"></canvas></div></div>\n\n    <div class=\"chart-row\">\n      <div class=\"chart-card\"><h3>Diritto vs Rovescio (net)</h3><div class=\"chart-wrap\"><canvas id=\"c-dr\"></canvas></div></div>\n      <div class=\"chart-card\"><h3>Fase di gioco (net)</h3><div class=\"chart-wrap\"><canvas id=\"c-fase\"></canvas></div></div>\n    </div>\n\n    <div class=\"chart-row\">\n      <div class=\"chart-card\"><h3>Servizio</h3><div class=\"chart-wrap\"><canvas id=\"c-servizio\"></canvas></div></div>\n      <div class=\"chart-card\"><h3>Risposta 1\u00aa vs 2\u00aa (net)</h3><div class=\"chart-wrap\"><canvas id=\"c-risposta\"></canvas></div></div>\n    </div>\n\n    <div class=\"chart-card\" id=\"serve-advanced-card\" style=\"display:none;\">\n      <h3>Statistiche avanzate sul servizio</h3>\n      <div id=\"serve-advanced-body\"></div>\n    </div>\n\n    <div class=\"chart-card\" id=\"error-zone-card\" style=\"display:none;\">\n      <h3>Zona degli errori \u2014 ${meta.allievo}</h3>\n      <div id=\"error-zone-body\"></div>\n    </div>\n\n    <div class=\"chart-card\"><h3>Colpi speciali (net)</h3><div class=\"chart-wrap\"><canvas id=\"c-speciali\"></canvas></div></div>\n\n    <div class=\"chart-row\">\n      <div class=\"chart-card\"><h3>Composizione errori \u2014 ${meta.allievo}</h3><div class=\"chart-wrap\"><canvas id=\"c-err-a\"></canvas></div></div>\n      <div class=\"chart-card\"><h3>Composizione errori \u2014 ${meta.avversario}</h3><div class=\"chart-wrap\"><canvas id=\"c-err-v\"></canvas></div></div>\n    </div>\n\n    <div class=\"chart-card\"><h3>Andamento del match (punti cumulati)</h3><div class=\"chart-wrap\"><canvas id=\"c-momentum\"></canvas></div></div>\n\n  `;\n\n  // stat grid\n  const grid = document.getElementById('stat-grid');\n  const aces = stats.servizio.ace, df = stats.servizio.doppio_fallo;\n  const cards = [\n    [`Punti (stima) ${meta.allievo}`, score.allievo],\n    [`Punti (stima) ${meta.avversario}`, score.avversario],\n    ['Punti totali stimati', totalPts],\n    ['Ace '+meta.allievo, aces.allievo],\n    ['Ace '+meta.avversario, aces.avversario],\n    ['Doppi falli '+meta.allievo, df.allievo],\n    ['Doppi falli '+meta.avversario, df.avversario],\n  ];\n  grid.innerHTML = cards.map(c=>`<div class=\"stat-card\"><div class=\"v\">${c[1]}</div><div class=\"l\">${c[0]}</div></div>`).join('');\n\n  if(totalPts === 0){\n    const emptyMsg = '<div class=\"chart-fallback\">\ud83d\udcc9 Nessun dato tecnico registrato. Il grafico comparir\u00e0 dopo i primi punti.</div>';\n    ['c-overview','c-dr','c-fase','c-servizio','c-risposta','c-speciali','c-err-a','c-err-v','c-momentum'].forEach(id=>{\n      const el = document.getElementById(id);\n      if(el && el.parentElement) el.parentElement.innerHTML = emptyMsg;\n    });\n  } else {\n  // ---- overview: winner / ef / enf totals per player, across everything except servizio (kept separate) ----\n  const allSets = [];\n  GROUPED_SHOTS.forEach(g=> SUBFASI.forEach(f=> allSets.push(stats[g.key][f.key])));\n  SIMPLE_SHOTS.forEach(sh=> allSets.push(stats[sh.key]));\n  RISPOSTA_FASI.forEach(f=> allSets.push(stats.risposta[f.key]));\n  const overview = sumResultSets(allSets);\n\n  mkChart(document.getElementById('c-overview'), {\n    type:'bar',\n    data:{\n      labels:['Winner','Errori Forzati','Errori Non Forzati'],\n      datasets:[\n        {label:meta.allievo, data:[overview.winner.allievo, overview.errori_forzati.allievo, overview.errori_non_forzati.allievo], backgroundColor:'#59a6ff'},\n        {label:meta.avversario, data:[overview.winner.avversario, overview.errori_forzati.avversario, overview.errori_non_forzati.avversario], backgroundColor:'#ff6f9c'}\n      ]\n    },\n    options:{responsive:true,maintainAspectRatio:false, scales:{y:{beginAtZero:true, ticks:{precision:0}}}}\n  });\n\n  // ---- diritto vs rovescio net ----\n  const drNet = GROUPED_SHOTS.map(g=>{\n    const sets = SUBFASI.map(f=>stats[g.key][f.key]);\n    const summed = sumResultSets(sets);\n    return netForResultSet(summed);\n  });\n  mkChart(document.getElementById('c-dr'), {\n    type:'bar',\n    data:{\n      labels: GROUPED_SHOTS.map(g=>g.label),\n      datasets:[\n        {label:meta.allievo, data:drNet.map(d=>d.allievo), backgroundColor:'#59a6ff'},\n        {label:meta.avversario, data:drNet.map(d=>d.avversario), backgroundColor:'#ff6f9c'}\n      ]\n    },\n    options:{responsive:true,maintainAspectRatio:false, scales:{y:{beginAtZero:true}}}\n  });\n\n  // ---- fase di gioco net (attacco/manovra/difesa aggregating diritto+rovescio) ----\n  const faseNet = SUBFASI.map(f=>{\n    const sets = GROUPED_SHOTS.map(g=>stats[g.key][f.key]);\n    return netForResultSet(sumResultSets(sets));\n  });\n  mkChart(document.getElementById('c-fase'), {\n    type:'bar',\n    data:{\n      labels: SUBFASI.map(f=>f.label),\n      datasets:[\n        {label:meta.allievo, data:faseNet.map(d=>d.allievo), backgroundColor:'#59a6ff'},\n        {label:meta.avversario, data:faseNet.map(d=>d.avversario), backgroundColor:'#ff6f9c'}\n      ]\n    },\n    options:{responsive:true,maintainAspectRatio:false, scales:{y:{beginAtZero:true}}}\n  });\n\n  // ---- servizio ----\n  mkChart(document.getElementById('c-servizio'), {\n    type:'bar',\n    data:{\n      labels:['Ace','Doppio Fallo'],\n      datasets:[\n        {label:meta.allievo, data:[stats.servizio.ace.allievo, stats.servizio.doppio_fallo.allievo], backgroundColor:'#59a6ff'},\n        {label:meta.avversario, data:[stats.servizio.ace.avversario, stats.servizio.doppio_fallo.avversario], backgroundColor:'#ff6f9c'}\n      ]\n    },\n    options:{responsive:true,maintainAspectRatio:false, scales:{y:{beginAtZero:true}}}\n  });\n\n  // ---- risposta net ----\n  const rispNet = RISPOSTA_FASI.map(f=> netForResultSet(stats.risposta[f.key]));\n  mkChart(document.getElementById('c-risposta'), {\n    type:'bar',\n    data:{\n      labels: RISPOSTA_FASI.map(f=>f.label),\n      datasets:[\n        {label:meta.allievo, data:rispNet.map(d=>d.allievo), backgroundColor:'#59a6ff'},\n        {label:meta.avversario, data:rispNet.map(d=>d.avversario), backgroundColor:'#ff6f9c'}\n      ]\n    },\n    options:{responsive:true,maintainAspectRatio:false, scales:{y:{beginAtZero:true}}}\n  });\n\n  // ---- colpi speciali net ----\n  const specNet = SIMPLE_SHOTS.map(sh=> netForResultSet(stats[sh.key]));\n  mkChart(document.getElementById('c-speciali'), {\n    type:'bar',\n    data:{\n      labels: SIMPLE_SHOTS.map(s=>s.label),\n      datasets:[\n        {label:meta.allievo, data:specNet.map(d=>d.allievo), backgroundColor:'#59a6ff'},\n        {label:meta.avversario, data:specNet.map(d=>d.avversario), backgroundColor:'#ff6f9c'}\n      ]\n    },\n    options:{responsive:true,maintainAspectRatio:false, scales:{y:{beginAtZero:true}}}\n  });\n\n  // ---- error composition doughnuts ----\n  mkChart(document.getElementById('c-err-a'), {\n    type:'doughnut',\n    data:{ labels:['Forzati','Non Forzati'], datasets:[{data:[overview.errori_forzati.allievo, overview.errori_non_forzati.allievo], backgroundColor:['#e08a6b','#e3b23c']}] },\n    options:{responsive:true,maintainAspectRatio:false}\n  });\n  mkChart(document.getElementById('c-err-v'), {\n    type:'doughnut',\n    data:{ labels:['Forzati','Non Forzati'], datasets:[{data:[overview.errori_forzati.avversario, overview.errori_non_forzati.avversario], backgroundColor:['#e08a6b','#e3b23c']}] },\n    options:{responsive:true,maintainAspectRatio:false}\n  });\n\n  // ---- momentum line ----\n  let cumA=0, cumV=0;\n  const momentum = [0];\n  record.log.forEach(entry=>{\n    const isWinnerLike = entry.path[entry.path.length-1] === 'winner' || entry.path[entry.path.length-1] === 'ace';\n    if(isWinnerLike){\n      if(entry.player==='allievo') cumA++; else cumV++;\n    } else {\n      if(entry.player==='allievo') cumV++; else cumA++;\n    }\n    momentum.push(cumA - cumV);\n  });\n  mkChart(document.getElementById('c-momentum'), {\n    type:'line',\n    data:{\n      labels: momentum.map((_,i)=>i),\n      datasets:[{\n        label:`Differenza punti (${meta.allievo} - ${meta.avversario})`,\n        data: momentum, borderColor:'#d7ff4e', backgroundColor:'rgba(215,255,78,0.12)', fill:true, tension:.25, pointRadius:0\n      }]\n    },\n    options:{responsive:true,maintainAspectRatio:false, plugins:{legend:{display:false}}, scales:{x:{display:false}}}\n  });\n  }\n\n  // ---- statistiche avanzate sul servizio (ace%, prima in campo, break point) ----\n  // Disponibili solo per le partite registrate dopo l'introduzione di questa\n  // funzionalit\u00e0 (i punti devono essere taggati con chi serviva).\n  const serveCard = document.getElementById('serve-advanced-card');\n  const serveBody = document.getElementById('serve-advanced-body');\n  const serveStats = (window.__MT_COMPUTE_SERVE_STATS__ && record.log) ? window.__MT_COMPUTE_SERVE_STATS__(record.log) : null;\n  if(serveStats && serveCard && serveBody){\n    serveCard.style.display = '';\n    const aces = stats.servizio.ace, df = stats.servizio.doppio_fallo;\n    const row = (label, a, v) => `\n      <div class=\"row\" style=\"padding:8px 0;border-bottom:1px solid var(--line);\">\n        <span class=\"muted\" style=\"font-size:13px;\">${label}</span>\n        <span style=\"font-family:'Oswald';font-size:14px;\"><span style=\"color:var(--allievo)\">${a}</span> \u00b7 <span style=\"color:var(--avversario)\">${v}</span></span>\n      </div>`;\n    const a = serveStats.allievo, v = serveStats.avversario;\n    serveBody.innerHTML = `\n      <div class=\"muted\" style=\"font-size:11px;text-transform:uppercase;letter-spacing:.5px;margin:10px 0 4px;\">${meta.allievo} vs ${meta.avversario}</div>\n      ${row('Ace', aces.allievo, aces.avversario)}\n      ${row('Doppi falli', df.allievo, df.avversario)}\n      ${row('Prima in campo', a.firstInPct!=null?a.firstInPct+'%':'\u2014', v.firstInPct!=null?v.firstInPct+'%':'\u2014')}\n      ${row('Punti vinti con la prima', a.wonOnFirstPct!=null?a.wonOnFirstPct+'%':'\u2014', v.wonOnFirstPct!=null?v.wonOnFirstPct+'%':'\u2014')}\n      ${row('Punti vinti con la seconda', a.wonOnSecondPct!=null?a.wonOnSecondPct+'%':'\u2014', v.wonOnSecondPct!=null?v.wonOnSecondPct+'%':'\u2014')}\n      ${row('Palle break salvate', a.bpFaced? `${a.bpSaved}/${a.bpFaced} (${a.bpSavedPct}%)` : '\u2014', v.bpFaced? `${v.bpSaved}/${v.bpFaced} (${v.bpSavedPct}%)` : '\u2014')}\n      ${row('Palle break convertite', a.bpConverted, v.bpConverted)}\n    `;\n  } else if(serveCard){\n    serveCard.style.display = 'none';\n  }\n\n  // ---- card visiva: zona degli errori (campo SVG con intensit\u00e0 per zona) ----\n  const zoneCard = document.getElementById('error-zone-card');\n  const zoneBody = document.getElementById('error-zone-body');\n  if(zoneCard && zoneBody){\n    if(zoneTotal >= 3){\n      zoneCard.style.display = '';\n      const ZONE_LABELS_SHORT = { lungo: 'Lunga', largo_sx: 'Larga sx', largo_dx: 'Larga dx', rete: 'In rete' };\n      const legendRows = Object.entries(zoneCounts).sort((a,b)=>b[1]-a[1]).map(([zone,count])=>\n        `<div class=\"row\" style=\"padding:4px 0;font-size:12.5px;\"><span class=\"muted\">${ZONE_LABELS_SHORT[zone]||zone}</span><span style=\"font-family:'Oswald';\">${count} (${Math.round(100*count/zoneTotal)}%)</span></div>`\n      ).join('');\n      zoneBody.innerHTML = `\n        ${buildCourtSVG('heatmap', {zoneCounts, zoneTotal})}\n        <div style=\"margin-top:10px;\">${legendRows}</div>\n        <p class=\"muted\" style=\"font-size:11.5px;margin-top:8px;\">Basato su ${zoneTotal} errori con zona registrata durante la partita.</p>\n      `;\n    } else {\n      zoneCard.style.display = '';\n      zoneBody.innerHTML = `<div class=\"chart-fallback\">\ud83d\udccd Non ci sono ancora abbastanza errori con zona registrata (minimo 3) per mostrare la mappa del campo.</div>`;\n    }\n  }\n\n  // export handlers\n  document.getElementById('btn-export-json').onclick = ()=> downloadFile(`${meta.allievo}_vs_${meta.avversario}_${meta.data}.json`, JSON.stringify(record, null, 2), 'application/json');\n  document.getElementById('btn-export-csv').onclick = ()=> downloadFile(`${meta.allievo}_vs_${meta.avversario}_${meta.data}.csv`, buildCSV(record), 'text/csv');\n  document.getElementById('btn-print').onclick = ()=> window.print();\n  document.getElementById('btn-newmatch').onclick = goToNewMatch;\n}\n\nfunction buildCSV(record){\n  const rows = [['timestamp','set','game','percorso','giocatore']];\n  record.log.forEach(e=>{\n    rows.push([new Date(e.ts).toISOString(), e.set, e.game, e.path.join('>'), e.player]);\n  });\n  return rows.map(r=>r.map(c=>`\"${String(c).replace(/\"/g,'\"\"')}\"`).join(',')).join('\\n');\n}\n\nfunction downloadFile(filename, content, mime){\n  const blob = new Blob([content], {type:mime});\n  const url = URL.createObjectURL(blob);\n  const a = document.createElement('a');\n  a.href = url; a.download = filename;\n  document.body.appendChild(a); a.click(); a.remove();\n  URL.revokeObjectURL(url);\n}\n\n\n\n/* ============================================================\n   NAV\n============================================================ */\ndocument.getElementById('navlinks').addEventListener('click', (e)=>{\n  const btn = e.target.closest('button[data-view]');\n  if(!btn) return;\n  if(btn.dataset.view === 'tracker' && !state) return;\n  if(btn.dataset.view === 'report' && !state) return;\n  showView(btn.dataset.view);\n});\n\n/* ============================================================\n   INIT\n============================================================ */\ndocument.getElementById('inp-data').value = new Date().toISOString().slice(0,10);\nif(window.__MT_ATHLETE__){\n  const inpAllievo = document.getElementById('inp-allievo');\n  inpAllievo.value = window.__MT_ATHLETE__.full_name;\n  inpAllievo.readOnly = true;\n  inpAllievo.style.opacity = '0.75';\n}\ntry{ buildFormatSelect(); }catch(e){ console.error('buildFormatSelect failed', e); }\ntry{ checkResume(); }catch(e){ console.error('checkResume failed', e); }\n\n})();";

function TrackerInner() {
  const params = useSearchParams();
  const router = useRouter();
  const athleteId = params.get('athleteId');
  const containerRef = useRef(null);
  const initialized = useRef(false);
  const [status, setStatus] = useState('loading');
  const [errorMsg, setErrorMsg] = useState('');

  useEffect(() => {
    (async () => {
      if (!athleteId) {
        setStatus('error');
        setErrorMsg('Nessun allievo selezionato: torna alla dashboard e apri la scheda di un allievo.');
        return;
      }
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) { router.push('/login'); return; }
      const staffToken = localStorage.getItem('staff_token');
      if (!staffToken) { router.push('/pin'); return; }
      const { data: athlete, error } = await supabase
        .from('athletes')
        .select('id, full_name, academy_id')
        .eq('id', athleteId)
        .single();
      if (error || !athlete) {
        setStatus('error');
        setErrorMsg('Allievo non trovato (o non è collegato al tuo account).');
        return;
      }
      window.__MT_SUPABASE__ = supabase;
      window.__MT_ACADEMY_ID__ = session.user.id;
      window.__MT_STAFF_ID__ = localStorage.getItem('staff_id') || null;
      window.__MT_STAFF_NAME__ = localStorage.getItem('staff_name') || null;
      window.__MT_ATHLETE__ = { id: athlete.id, full_name: athlete.full_name };
      window.__MT_GET_SERVER__ = getCurrentServer;
      window.__MT_WOULD_WIN_GAME__ = wouldWinGame;
      window.__MT_COMPUTE_SERVE_STATS__ = computeServeStats;
      setStatus('ready');
    })();
  }, [athleteId]);

  useEffect(() => {
    if (status !== 'ready' || initialized.current) return;
    initialized.current = true;
    try {
      // eslint-disable-next-line no-new-func
      const run = new Function(TRACKER_SCRIPT);
      run();
    } catch (e) {
      console.error('errore avvio tracker:', e);
    }
  }, [status]);

  if (status === 'error') {
    return (
      <div style={{maxWidth:640, margin:'60px auto', padding:20, textAlign:'center', fontFamily:'sans-serif'}}>
        <p>⚠️ {errorMsg}</p>
        <a href="/dashboard">← Torna alla dashboard</a>
      </div>
    );
  }

  return (
    <>
      <style dangerouslySetInnerHTML={{ __html: TRACKER_CSS }} />
      <div className="app" ref={containerRef} dangerouslySetInnerHTML={{ __html: TRACKER_BODY_HTML }} />
    </>
  );
}

export default function TrackerPage() {
  return (
    <Suspense fallback={<div style={{padding:40, textAlign:'center'}}>Caricamento…</div>}>
      <TrackerInner />
    </Suspense>
  );
}
